function BarterModal({locale,data,error,close,save}:{locale:Locale;data:Data;error:string;close:()=>void;save:(v:BarterDraft)=>void}){
  const first=data.products[0]?.id??"";const second=data.products[1]?.id??first;const [step,setStep]=useState(1);const [form,setForm]=useState<BarterDraft>({branch:data.branches[0]?.id??"",customer:"",mode:"single",primaryProductId:first,primaryQuantity:2,outgoingItems:[{productId:first,quantity:2}],exchangeProductId:second,ratioBase:2,ratioExchange:1,incomingItems:[],notes:""});const primaryBalance=data.inventory.find(i=>i.branchId===form.branch&&i.productId===form.primaryProductId);const calculated=form.ratioBase>0?form.primaryQuantity/form.ratioBase*form.ratioExchange:0;
  function addLine(){const product=data.products.find(p=>!form.outgoingItems.some(i=>i.productId===p.id));if(product)setForm({...form,outgoingItems:[...form.outgoingItems,{productId:product.id,quantity:1}]})}function updateLine(index:number,values:Partial<{productId:string;quantity:number}>){setForm({...form,outgoingItems:form.outgoingItems.map((item,i)=>i===index?{...item,...values}:item)})}
  return <div className="fixed inset-0 z-50 grid place-items-center bg-slate-950/60 p-3"><form onSubmit={e=>{e.preventDefault();if(step===1)setStep(2);else save(form)}} className="card max-h-[95vh] w-full max-w-4xl overflow-y-auto p-6"><div className="flex"><div><p className="text-sm font-bold text-brand-600">{locale==="ar"?`الخطوة ${step} من 2`:`Step ${step} of 2`}</p><h2 className="text-2xl font-bold">{locale==="ar"?"إذن مقايضة منتجات":"Product Barter Voucher"}</h2></div><button type="button" onClick={close} className="ms-auto"><X/></button></div>{step===1?<div className="py-12"><Building2 className="mx-auto text-brand-600" size={46}/><h3 className="mt-4 text-center text-xl font-bold">{locale==="ar"?"اختر الفرع أولًا":"Choose branch first"}</h3><div className="mx-auto mt-6 max-w-md"><SelectField label={locale==="ar"?"الفرع / المخزن":"Branch / warehouse"} value={form.branch} set={branch=>setForm({...form,branch})} items={data.branches.map(b=>({id:b.id,label:locale==="ar"?b.nameAr:b.nameEn}))}/></div></div>:<div><div className="mt-5 grid gap-3 sm:grid-cols-2"><button type="button" onClick={()=>setForm({...form,mode:"single"})} className={`rounded-2xl border-2 p-4 text-start ${form.mode==="single"?"border-brand-500 bg-brand-50":"border-slate-200"}`}><strong>{locale==="ar"?"منتج داخل مقابل منتج خارج":"One in for one out"}</strong><p className="text-sm text-slate-500">{locale==="ar"?"منتج واحد يدخل ومنتج واحد يخرج بنسبة":"One incoming and one outgoing"}</p></button><button type="button" onClick={()=>setForm({...form,mode:"multi"})} className={`rounded-2xl border-2 p-4 text-start ${form.mode==="multi"?"border-brand-500 bg-brand-50":"border-slate-200"}`}><strong>{locale==="ar"?"منتج داخل مقابل منتجات خارجة":"One in for multiple out"}</strong><p className="text-sm text-slate-500">{locale==="ar"?"منتج واحد يأتي من الخارج وعدة منتجات تخرج من عندنا":"One incoming, multiple outgoing"}</p></button></div><div className="mt-5 grid gap-4 sm:grid-cols-2"><Field label={locale==="ar"?"العميل أو الطرف الآخر":"Customer or other party"} value={form.customer} set={customer=>setForm({...form,customer})}/><div/><label className="text-sm">{locale==="ar"?"المنتج الداخل للمخزن":"Incoming product"}<select className="input mt-2" value={form.exchangeProductId} onChange={e=>setForm({...form,exchangeProductId:e.target.value})}>{data.products.map(p=><option key={p.id} value={p.id}>{locale==="ar"?p.nameAr:p.nameEn}</option>)}</select></label>{form.mode==="multi"&&<label className="text-sm">{locale==="ar"?"الكمية الداخلة":"Incoming quantity"}<input min="0.001" step="0.001" type="number" className="input mt-2" value={form.ratioExchange} onChange={e=>setForm({...form,ratioExchange:Number(e.target.value)})}/></label>}</div>{form.mode==="single"?<div className="mt-5 grid gap-4 sm:grid-cols-3"><label className="text-sm">{locale==="ar"?"المنتج الخارج":"Outgoing product"}<select className="input mt-2" value={form.primaryProductId} onChange={e=>setForm({...form,primaryProductId:e.target.value})}>{data.products.map(p=><option key={p.id} value={p.id}>{locale==="ar"?p.nameAr:p.nameEn}</option>)}</select><small className="text-slate-500">{locale==="ar"?"المتاح":"Available"}: {primaryBalance?.availableQuantity??0}</small></label><label className="text-sm">{locale==="ar"?"لكل كمية خارجة":"For every outgoing"}<input min="0.001" step="0.001" type="number" className="input mt-2" value={form.ratioBase} onChange={e=>setForm({...form,ratioBase:Number(e.target.value),primaryQuantity:Number(e.target.value)})}/></label><label className="text-sm">{locale==="ar"?"تدخل كمية":"Incoming quantity"}<input min="0.001" step="0.001" type="number" className="input mt-2" value={form.ratioExchange} onChange={e=>setForm({...form,ratioExchange:Number(e.target.value)})}/></label><div className="rounded-xl bg-brand-50 p-4 text-brand-700 sm:col-span-3">-{form.primaryQuantity} {name(data.products,form.primaryProductId,locale)} &nbsp; +{Number(calculated.toFixed(3))} {name(data.products,form.exchangeProductId,locale)}</div></div>:<div className="mt-5"><h3 className="mb-3 font-bold">{locale==="ar"?"المنتجات الخارجة من عندنا":"Outgoing products"}</h3><div className="space-y-3">{form.outgoingItems.map((item,index)=>{const stock=data.inventory.find(i=>i.branchId===form.branch&&i.productId===item.productId)?.availableQuantity??0;return <div className="grid gap-3 rounded-xl bg-slate-50 p-3 dark:bg-slate-800 sm:grid-cols-[1fr_150px_90px_45px]" key={index}><select className="input" value={item.productId} onChange={e=>updateLine(index,{productId:e.target.value})}>{data.products.map(p=><option key={p.id} value={p.id}>{locale==="ar"?p.nameAr:p.nameEn}</option>)}</select><input min="0.001" step="0.001" type="number" className="input" value={item.quantity} onChange={e=>updateLine(index,{quantity:Number(e.target.value)})}/><span className="self-center text-sm text-slate-500">{locale==="ar"?"متاح":"Stock"}: {stock}</span><button type="button" onClick={()=>setForm({...form,outgoingItems:form.outgoingItems.filter((_,i)=>i!==index)})} className="text-red-600"><Trash2/></button></div>})}</div><button disabled={form.outgoingItems.length>=data.products.length} type="button" onClick={addLine} className="btn-secondary mt-3"><Plus size={16}/>{locale==="ar"?"إضافة منتج خارج":"Add outgoing product"}</button></div>}<label className="mt-5 block text-sm">{locale==="ar"?"ملاحظات":"Notes"}<textarea className="input mt-2 min-h-20" value={form.notes} onChange={e=>setForm({...form,notes:e.target.value})}/></label>{error&&<p className="mt-4 rounded-xl bg-red-50 p-3 text-red-700">{error}</p>}</div>}<div className="mt-6 flex justify-end gap-2 border-t pt-5"><button type="button" onClick={step===1?close:()=>setStep(1)} className="btn-secondary">{step===1?(locale==="ar"?"إلغاء":"Cancel"):(locale==="ar"?"رجوع":"Back")}</button><button className="btn-primary">{step===1?(locale==="ar"?"التالي":"Next"):(locale==="ar"?"اعتماد المقايضة":"Post barter")}</button></div></form></div>;
}

function CustodyPage({locale,data,setData,toast}:{locale:Locale;data:Data;setData:React.Dispatch<React.SetStateAction<Data>>;toast:(s?:string)=>void}){
  const t=useTranslations();const [open,setOpen]=useState(false);const [settling,setSettling]=useState<RepresentativeCustody|null>(null);const [error,setError]=useState("");const rows=data.custodies??[];
  function lineName(line:RepresentativeCustodyLine){if(line.kind==="package"){const pkg=data.packages.find(x=>x.id===line.itemId);return `${locale==="ar"?"باكيدج":"Package"}: ${pkg?(locale==="ar"?pkg.nameAr:pkg.nameEn):"—"}`}return name(data.products,line.itemId,locale)}
  function lineAvailable(line:RepresentativeCustodyLine,branchId:string){if(line.kind==="package"){const pkg=data.packages.find(x=>x.id===line.itemId);return pkg?packageCapacity(data,pkg,branchId):0}return data.inventory.find(i=>i.branchId===branchId&&i.productId===line.itemId)?.availableQuantity??0}
  function add(v:CustodyDraft){setError("");if(!v.branch||!v.representativeName.trim()||!v.date||!v.lines.length||v.lines.some(line=>!line.itemId||line.quantity<=0)){setError(locale==="ar"?"راجع اسم المندوب والتاريخ والكميات":"Check representative, date, and quantities");return}for(const line of v.lines){const stock=lineAvailable(line,v.branch);if(line.quantity>stock){setError(`${locale==="ar"?"الرصيد غير كافٍ لـ":"Insufficient stock for"} ${lineName(line)} (${stock})`);return}}const stamp=Date.now();const custody:RepresentativeCustody={id:`custody-${stamp}`,number:`CST-${String(rows.length+1).padStart(6,"0")}`,date:v.date,branchId:v.branch,representativeName:v.representativeName.trim(),lines:v.lines.map(line=>({...line,returnedQuantity:0,issuedQuantity:0})),notes:v.notes,status:"open"};setData(d=>({...d,custodies:[custody,...(d.custodies??[])]}));setOpen(false);toast(locale==="ar"?"تم تسجيل عهدة المندوب":"Representative custody recorded")}
  function settle(custody:RepresentativeCustody,lines:RepresentativeCustodyLine[]){setError("");if(lines.some(line=>(line.returnedQuantity??0)<0||(line.returnedQuantity??0)>line.quantity)){setError(locale==="ar"?"المرتجع لا يمكن أن يكون أكبر من الكمية المستلمة":"Returned quantity cannot exceed received quantity");return}for(const line of lines){const actual=line.quantity-(line.returnedQuantity??0);if(actual>lineAvailable({...line,quantity:actual},custody.branchId)){setError(`${locale==="ar"?"الرصيد غير كافٍ لتسوية":"Insufficient stock to settle"} ${lineName(line)}`);return}}const date=new Date().toISOString().slice(0,10);setData(d=>{let inventory=d.inventory;const stamp=Date.now();const movements:StockMovement[]=[];for(const [index,line] of lines.entries()){const actual=line.quantity-(line.returnedQuantity??0);if(actual<=0)continue;if(line.kind==="package"){const pkg=d.packages.find(x=>x.id===line.itemId);if(!pkg)continue;inventory=postPackageInventory(inventory,custody.branchId,pkg,actual,date);movements.push(...pkg.items.map((item,i):StockMovement=>({id:`m-cst-pkg-out-${stamp}-${index}-${i}`,date,type:"Custody Package Settlement",branchId:custody.branchId,productId:item.productId,quantity:-(item.quantity*actual),reference:custody.number,user:custody.representativeName,note:pkg.nameAr})),{id:`m-cst-pkg-in-${stamp}-${index}`,date,type:"Custody Package Return",branchId:custody.branchId,productId:pkg.returnProductId,quantity:pkg.returnQuantity*actual,reference:custody.number,user:custody.representativeName,note:pkg.nameAr})}else{inventory=inventory.map(balance=>{if(balance.branchId!==custody.branchId||balance.productId!==line.itemId)return balance;const current=balance.currentQuantity-actual;const availableQty=current-balance.reservedQuantity;return {...balance,currentQuantity:current,availableQuantity:availableQty,inventoryValue:calculateInventoryValue(current,balance.averageCost),lastMovementDate:date,status:getStockStatus(availableQty,balance.minimumQuantity,balance.maximumQuantity)}});movements.push({id:`m-cst-${stamp}-${index}`,date,type:"Custody Settlement",branchId:custody.branchId,productId:line.itemId,quantity:-actual,reference:custody.number,user:custody.representativeName,note:locale==="ar"?"تسوية عهدة مندوب":"Representative custody settlement"})}}return {...d,inventory,movements:[...movements,...d.movements],custodies:(d.custodies??[]).map(x=>x.id===custody.id?{...x,settlementDate:date,lines:lines.map(line=>({...line,issuedQuantity:line.quantity-(line.returnedQuantity??0)})),status:"settled"}:x)}});setSettling(null);toast(locale==="ar"?"تمت تسوية العهدة وخصم المصروف الفعلي":"Custody settled and actual issued stock deducted")}
  return <><ListLayout title={t("custody")} search="" setSearch={()=>{}} actions={<button disabled={!data.products.length&&!data.packages.length} onClick={()=>setOpen(true)} className="btn-primary"><ClipboardCheck size={17}/>{locale==="ar"?"عهدة جديدة":"New custody"}</button>}><Table headers={[locale==="ar"?"رقم العهدة":"No.",t("date"),t("branch"),locale==="ar"?"المندوب":"Representative",locale==="ar"?"العهدة المستلمة":"Received custody",locale==="ar"?"المصروف الفعلي":"Actual issued",t("status"),t("actions")]} empty={!rows.length}>{rows.map(row=><tr key={row.id}><Cell strong>{row.number}</Cell><Cell>{row.date}{row.settlementDate?` / ${row.settlementDate}`:""}</Cell><Cell>{name(data.branches,row.branchId,locale)}</Cell><Cell>{row.representativeName}</Cell><Cell><div className="space-y-1">{row.lines.map((line,index)=><div key={index}>{line.quantity} × {lineName(line)}</div>)}</div></Cell><Cell><div className="space-y-1">{row.lines.map((line,index)=><div className="font-semibold text-red-600" key={index}>-{line.issuedQuantity??0} {lineName(line)}</div>)}</div></Cell><Cell><Status value={row.status}/></Cell><Cell>{row.status==="open"?<button onClick={()=>{setError("");setSettling(row)}} className="btn-primary px-3 py-1.5"><ClipboardCheck size={15}/>{locale==="ar"?"تسوية العهدة":"Settle"}</button>:<span className="text-xs text-slate-400">-</span>}</Cell></tr>)}</Table></ListLayout>{open&&<CustodyModal locale={locale} data={data} error={error} close={()=>{setOpen(false);setError("")}} save={add}/>} {settling&&<CustodySettlementModal locale={locale} data={data} custody={settling} error={error} close={()=>{setSettling(null);setError("")}} save={lines=>settle(settling,lines)}/>}</>;
}

function CustodyModal({locale,data,error,close,save}:{locale:Locale;data:Data;error:string;close:()=>void;save:(v:CustodyDraft)=>void}){
  const firstProduct=data.products[0]?.id??"";const firstPackage=data.packages.find(x=>x.status!=="inactive")?.id??"";const [form,setForm]=useState<CustodyDraft>({branch:data.branches[0]?.id??"",representativeName:"",date:new Date().toISOString().slice(0,10),notes:"",lines:[{kind:firstPackage?"package":"product",itemId:firstPackage||firstProduct,quantity:1}]});
  function addLine(){setForm({...form,lines:[...form.lines,{kind:firstProduct?"product":"package",itemId:firstProduct||firstPackage,quantity:1}]})}function update(index:number,values:Partial<RepresentativeCustodyLine>){setForm({...form,lines:form.lines.map((line,i)=>i===index?{...line,...values}:line)})}
  return <div className="fixed inset-0 z-50 grid place-items-center bg-slate-950/60 p-3"><form onSubmit={e=>{e.preventDefault();save(form)}} className="card max-h-[95vh] w-full max-w-4xl overflow-y-auto p-6"><div className="flex"><div><h2 className="text-2xl font-bold">{locale==="ar"?"عهدة مندوب جديدة":"New representative custody"}</h2><p className="mt-1 text-sm text-slate-500">{locale==="ar"?"سجل الكمية التي سيستلمها المندوب من المخزن المحدد":"Record what the representative receives from the selected warehouse"}</p></div><button type="button" onClick={close} className="ms-auto"><X/></button></div><div className="mt-6 grid gap-4 sm:grid-cols-3"><SelectField label={locale==="ar"?"المخزن / الفرع":"Warehouse / branch"} value={form.branch} set={branch=>setForm({...form,branch})} items={data.branches.map(b=>({id:b.id,label:locale==="ar"?b.nameAr:b.nameEn}))}/><Field label={locale==="ar"?"اسم المندوب":"Representative name"} value={form.representativeName} set={representativeName=>setForm({...form,representativeName})}/><label className="text-sm">{locale==="ar"?"تاريخ الاستلام":"Receive date"}<input required type="date" className="input mt-2" value={form.date} onChange={e=>setForm({...form,date:e.target.value})}/></label></div><h3 className="mt-6 font-bold">{locale==="ar"?"المنتجات أو الباكيدجات المستلمة":"Received products or packages"}</h3><div className="mt-3 space-y-3">{form.lines.map((line,index)=><div className="grid gap-3 rounded-xl bg-slate-50 p-3 dark:bg-slate-800 sm:grid-cols-[130px_1fr_150px_45px]" key={index}><select className="input" value={line.kind} onChange={e=>{const kind=e.target.value as "product"|"package";update(index,{kind,itemId:kind==="package"?firstPackage:firstProduct})}}><option value="product">{locale==="ar"?"منتج":"Product"}</option><option value="package" disabled={!firstPackage}>{locale==="ar"?"باكيدج":"Package"}</option></select><select className="input" value={line.itemId} onChange={e=>update(index,{itemId:e.target.value})}>{line.kind==="package"?data.packages.filter(x=>x.status!=="inactive").map(pkg=><option key={pkg.id} value={pkg.id}>{locale==="ar"?pkg.nameAr:pkg.nameEn}</option>):data.products.map(p=><option key={p.id} value={p.id}>{locale==="ar"?p.nameAr:p.nameEn}</option>)}</select><input required min="0.001" step="0.001" type="number" className="input" value={line.quantity} onChange={e=>update(index,{quantity:Number(e.target.value)})}/><button type="button" disabled={form.lines.length===1} onClick={()=>setForm({...form,lines:form.lines.filter((_,i)=>i!==index)})} className="text-red-600 disabled:opacity-30"><Trash2/></button></div>)}</div><button type="button" onClick={addLine} className="btn-secondary mt-3"><Plus size={16}/>{locale==="ar"?"إضافة سطر عهدة":"Add custody line"}</button><label className="mt-5 block text-sm">{locale==="ar"?"ملاحظات":"Notes"}<textarea className="input mt-2 min-h-20" value={form.notes} onChange={e=>setForm({...form,notes:e.target.value})}/></label>{error&&<p className="mt-4 rounded-xl bg-red-50 p-3 text-red-700">{error}</p>}<div className="mt-6 flex justify-end gap-2 border-t pt-5"><button type="button" onClick={close} className="btn-secondary">{locale==="ar"?"إلغاء":"Cancel"}</button><button className="btn-primary">{locale==="ar"?"حفظ العهدة":"Save custody"}</button></div></form></div>;
}

function CustodySettlementModal({locale,data,custody,error,close,save}:{locale:Locale;data:Data;custody:RepresentativeCustody;error:string;close:()=>void;save:(lines:RepresentativeCustodyLine[])=>void}){
  const [lines,setLines]=useState(custody.lines.map(line=>({...line,returnedQuantity:line.returnedQuantity??0})));function lineName(line:RepresentativeCustodyLine){if(line.kind==="package"){const pkg=data.packages.find(x=>x.id===line.itemId);return `${locale==="ar"?"باكيدج":"Package"}: ${pkg?(locale==="ar"?pkg.nameAr:pkg.nameEn):"—"}`}return name(data.products,line.itemId,locale)}
  return <div className="fixed inset-0 z-50 grid place-items-center bg-slate-950/60 p-3"><form onSubmit={e=>{e.preventDefault();save(lines)}} className="card max-h-[95vh] w-full max-w-3xl overflow-y-auto p-6"><div className="flex"><div><p className="text-sm font-bold text-brand-600">{custody.number} · {name(data.branches,custody.branchId,locale)}</p><h2 className="text-2xl font-bold">{locale==="ar"?"تسوية عهدة المندوب":"Representative custody settlement"}</h2></div><button type="button" onClick={close} className="ms-auto"><X/></button></div><p className="mt-4 rounded-xl bg-brand-50 p-4 text-sm text-brand-700">{locale==="ar"?"اكتب الكمية التي رجع بها المندوب، وسيتم خصم الفرق فقط كمصروف فعلي من المخزن.":"Enter the returned quantity; only the difference will be deducted as actual issued stock."}</p><div className="mt-5 space-y-3">{lines.map((line,index)=>{const actual=line.quantity-(line.returnedQuantity??0);return <div className="grid gap-3 rounded-xl border border-slate-200 p-3 dark:border-slate-700 sm:grid-cols-[1fr_110px_130px_130px]" key={index}><strong className="self-center">{lineName(line)}</strong><span className="self-center text-sm text-slate-500">{locale==="ar"?"استلم":"Received"}: {line.quantity}</span><label className="text-sm">{locale==="ar"?"المرتجع":"Returned"}<input min="0" max={line.quantity} step="0.001" type="number" className="input mt-1" value={line.returnedQuantity??0} onChange={e=>setLines(lines.map((x,i)=>i===index?{...x,returnedQuantity:Number(e.target.value)}:x))}/></label><span className="self-center rounded-xl bg-red-50 px-3 py-2 text-sm font-bold text-red-700">{locale==="ar"?"المصروف":"Issued"}: {actual}</span></div>})}</div>{error&&<p className="mt-4 rounded-xl bg-red-50 p-3 text-red-700">{error}</p>}<div className="mt-6 flex justify-end gap-2 border-t pt-5"><button type="button" onClick={close} className="btn-secondary">{locale==="ar"?"إلغاء":"Cancel"}</button><button className="btn-primary">{locale==="ar"?"اعتماد تسوية العهدة":"Post settlement"}</button></div></form></div>;
}

function ProductModal({locale,branches,close,save}:{locale:Locale;branches:Branch[];close:()=>void;save:(v:{nameAr:string;nameEn:string;sku:string;price:number;unit:string;branch:string;quantity:number;imageUrl?:string})=>void}){
  const [form,setForm]=useState({nameAr:"",nameEn:"",sku:"",price:0,unit:locale==="ar"?"قطعة":"Piece",branch:branches[0]?.id??"",quantity:0,imageUrl:""});
  return <div className="fixed inset-0 z-50 grid place-items-center bg-slate-950/50 p-4"><form onSubmit={e=>{e.preventDefault();save(form)}} className="card max-h-[90vh] w-full max-w-xl overflow-y-auto p-6"><div className="flex"><h2 className="text-xl font-bold">{locale==="ar"?"إضافة منتج":"Add product"}</h2><button type="button" onClick={close} className="ms-auto"><X/></button></div><label className="mt-5 flex cursor-pointer items-center gap-4 rounded-2xl border-2 border-dashed border-slate-300 p-4"><ProductImage product={{imageUrl:form.imageUrl} as Product} size="lg"/><div><strong>{locale==="ar"?"صورة المنتج":"Product image"}</strong><p className="text-xs text-slate-500">{locale==="ar"?"اضغط لاختيار صورة — سيتم تصغيرها تلقائيًا":"Click to choose; image will be resized"}</p></div><input hidden type="file" accept="image/*" onChange={async e=>{const file=e.target.files?.[0];if(file)setForm({...form,imageUrl:await compressProductImage(file)})}}/></label><div className="mt-6 grid gap-4 sm:grid-cols-2"><Field label="الاسم بالعربية" value={form.nameAr} set={v=>setForm({...form,nameAr:v})}/><Field label="English name" value={form.nameEn} set={v=>setForm({...form,nameEn:v})}/><Field label="SKU" value={form.sku} set={v=>setForm({...form,sku:v})}/><label className="text-sm">{locale==="ar"?"سعر الشراء":"Purchase price"}<input required min="0.01" step="0.01" type="number" className="input mt-2" value={form.price||""} onChange={e=>setForm({...form,price:Number(e.target.value)})}/></label><label className="text-sm">{locale==="ar"?"الوحدة":"Unit"}<select className="input mt-2" value={form.unit} onChange={e=>setForm({...form,unit:e.target.value})}><option>{locale==="ar"?"قطعة":"Piece"}</option><option>{locale==="ar"?"كيلوجرام":"Kilogram"}</option><option>{locale==="ar"?"لتر":"Liter"}</option><option>{locale==="ar"?"كرتونة":"Carton"}</option></select></label><SelectField label={locale==="ar"?"فرع الرصيد الافتتاحي":"Opening stock branch"} value={form.branch} set={v=>setForm({...form,branch:v})} items={branches.map(b=>({id:b.id,label:locale==="ar"?b.nameAr:b.nameEn}))}/><label className="text-sm sm:col-span-2">{locale==="ar"?"الكمية الافتتاحية":"Opening quantity"}<input required min="0" type="number" className="input mt-2" value={form.quantity} onChange={e=>setForm({...form,quantity:Number(e.target.value)})}/></label></div><div className="mt-6 flex justify-end gap-2"><button type="button" onClick={close} className="btn-secondary">{locale==="ar"?"إلغاء":"Cancel"}</button><button className="btn-primary">{locale==="ar"?"إضافة المنتج":"Add product"}</button></div></form></div>;
}

function Field({label,value,set}:{label:string;value:string;set:(v:string)=>void}){return <label className="text-sm">{label}<input required minLength={2} className="input mt-2" value={value} onChange={e=>set(e.target.value)}/></label>}

function TransfersPage({locale,data,setData,toast}:{locale:Locale;data:Data;setData:React.Dispatch<React.SetStateAction<Data>>;toast:(s?:string)=>void}){
  const t=useTranslations();const [open,setOpen]=useState(false);const [error,setError]=useState("");
  function issue(v:{from:string;to:string;product:string;quantity:number}){setError("");if(!v.product){setError(locale==="ar"?"أضف منتجًا أولًا":"Add a product first");return}if(v.from===v.to){setError(locale==="ar"?"اختر فرعين مختلفين":"Choose different branches");return}const source=data.inventory.find(i=>i.branchId===v.from&&i.productId===v.product);if(!source||v.quantity<=0||v.quantity>source.availableQuantity){setError(locale==="ar"?`الكمية المتاحة ${source?.availableQuantity??0}`:`Available quantity: ${source?.availableQuantity??0}`);return}const date=new Date().toISOString().slice(0,10);setData(d=>{const updated=d.inventory.map(i=>{if(i.productId!==v.product||i.branchId!==v.from)return i;const current=i.currentQuantity-v.quantity;const available=current-i.reservedQuantity;return {...i,currentQuantity:current,availableQuantity:available,inventoryValue:calculateInventoryValue(current,i.averageCost),lastMovementDate:date,status:getStockStatus(available,i.minimumQuantity,i.maximumQuantity)}});const number=`TR-${Date.now().toString().slice(-7)}`;const newTransfer:Transfer={id:`t-${Date.now()}`,number,fromBranchId:v.from,toBranchId:v.to,productId:v.product,quantity:v.quantity,date,status:"sent",items:1};const movement:StockMovement={id:`m-out-${Date.now()}`,date,type:"Stock Issue",branchId:v.from,productId:v.product,quantity:-v.quantity,reference:number,user:locale==="ar"?"أمين المخزن":"Storekeeper"};return {...d,inventory:updated,transfers:[newTransfer,...d.transfers],movements:[movement,...d.movements]}});setOpen(false);toast(locale==="ar"?"تم إصدار إذن الصرف وفي انتظار استلام الفرع":"Issue voucher created; awaiting branch receipt")}
  function receive(transfer:Transfer){if(!transfer.productId||!transfer.quantity||transfer.status!=="sent")return;if(!confirm(locale==="ar"?`هل وافق الفرع على استلام ${transfer.quantity}؟`:`Confirm receipt of ${transfer.quantity}?`))return;const date=new Date().toISOString().slice(0,10);setData(d=>{const updated=d.inventory.map(i=>{if(i.productId!==transfer.productId||i.branchId!==transfer.toBranchId)return i;const current=i.currentQuantity+(transfer.quantity??0);const available=current-i.reservedQuantity;return {...i,currentQuantity:current,availableQuantity:available,inventoryValue:calculateInventoryValue(current,i.averageCost),lastMovementDate:date,status:getStockStatus(available,i.minimumQuantity,i.maximumQuantity)}});const movement:StockMovement={id:`m-in-${Date.now()}`,date,type:"Transfer Receipt",branchId:transfer.toBranchId,productId:transfer.productId!,quantity:transfer.quantity!,reference:transfer.number,user:locale==="ar"?"مسؤول الفرع المستلم":"Receiving branch"};return {...d,inventory:updated,transfers:d.transfers.map(x=>x.id===transfer.id?{...x,status:"received"}:x),movements:[movement,...d.movements]}});toast(locale==="ar"?"وافق الفرع وتمت إضافة الكمية إلى رصيده":"Branch approved and stock was received")}
  return <><ListLayout title={t("transfers")} search="" setSearch={()=>{}} actions={<button disabled={!data.products.length} onClick={()=>setOpen(true)} className="btn-primary"><ArrowLeftRight size={17}/>{locale==="ar"?"إذن صرف جديد":"New issue voucher"}</button>}><Table headers={[locale==="ar"?"رقم الإذن":"Voucher No.",t("date"),locale==="ar"?"المخزن الصارف":"Source",locale==="ar"?"الفرع المستلم":"Destination",t("product"),t("quantity"),t("status"),t("actions")]} empty={!data.transfers.length}>{data.transfers.map(x=><tr key={x.id}><Cell strong>{x.number}</Cell><Cell>{x.date}</Cell><Cell>{name(data.branches,x.fromBranchId,locale)}</Cell><Cell>{name(data.branches,x.toBranchId,locale)}</Cell><Cell>{x.productId?name(data.products,x.productId,locale):"—"}</Cell><Cell>{x.quantity??"—"}</Cell><Cell><Status value={x.status}/></Cell><Cell><div className="flex gap-2"><button onClick={()=>printVoucher(x,data,locale)} className="btn-secondary px-3 py-1.5"><Printer size={15}/>{locale==="ar"?"إذن الصرف":"Issue"}</button>{x.status==="sent"&&<button onClick={()=>receive(x)} className="btn-primary px-3 py-1.5">{locale==="ar"?"موافقة واستلام":"Approve & receive"}</button>}</div></Cell></tr>)}</Table></ListLayout>{!data.products.length&&<p className="mt-4 rounded-xl bg-amber-50 p-4 text-sm text-amber-800">{locale==="ar"?"أضف منتجًا ورصيدًا افتتاحيًا أولًا حتى تتمكن من إصدار إذن صرف.":"Add a product with opening stock before creating an issue voucher."}</p>}{open&&<TransferModal locale={locale} data={data} error={error} close={()=>{setOpen(false);setError("")}} save={issue}/>}</>;
}

function ReceiptsPage({locale,data,setData,toast}:{locale:Locale;data:Data;setData:React.Dispatch<React.SetStateAction<Data>>;toast:(s?:string)=>void}){
  const t=useTranslations();const [open,setOpen]=useState(false);const receipts=data.movements.filter(m=>m.type==="Purchase Receipt");
  function receive(v:{reference:string;supplier:string;branch:string;product:string;quantity:number;cost:number}){const date=new Date().toISOString().slice(0,10);setData(d=>{const updated=d.inventory.map(i=>{if(i.branchId!==v.branch||i.productId!==v.product)return i;const current=i.currentQuantity+v.quantity;const averageCost=current?((i.currentQuantity*i.averageCost)+(v.quantity*v.cost))/current:v.cost;const available=current-i.reservedQuantity;return {...i,currentQuantity:current,availableQuantity:available,averageCost,inventoryValue:calculateInventoryValue(current,averageCost),lastMovementDate:date,status:getStockStatus(available,i.minimumQuantity,i.maximumQuantity)}});const movement:StockMovement={id:`m-receipt-${Date.now()}`,date,type:"Purchase Receipt",branchId:v.branch,productId:v.product,quantity:v.quantity,reference:v.reference,user:locale==="ar"?"أمين المخزن":"Storekeeper",supplierName:v.supplier,unitCost:v.cost};return {...d,inventory:updated,movements:[movement,...d.movements]}});setOpen(false);toast(locale==="ar"?"تم استلام المشتريات وإضافة الكمية للمخزون":"Purchase received and stock updated")}
  return <><ListLayout title={t("receipts")} search="" setSearch={()=>{}} actions={<button disabled={!data.products.length||!data.suppliers.length} onClick={()=>setOpen(true)} className="btn-primary"><Plus size={17}/>{locale==="ar"?"إذن استلام جديد":"New receipt"}</button>}><Table headers={[locale==="ar"?"رقم الإذن":"Receipt No.",t("date"),locale==="ar"?"المورد":"Supplier",t("branch"),t("product"),t("quantity"),locale==="ar"?"سعر الوحدة":"Unit cost",t("value")]} empty={!receipts.length}>{receipts.map(m=><tr key={m.id}><Cell strong>{m.reference}</Cell><Cell>{m.date}</Cell><Cell>{m.supplierName??"—"}</Cell><Cell>{name(data.branches,m.branchId,locale)}</Cell><Cell>{name(data.products,m.productId,locale)}</Cell><Cell>{m.quantity}</Cell><Cell>{m.unitCost?.toLocaleString()??"—"} EGP</Cell><Cell>{((m.unitCost??0)*m.quantity).toLocaleString()} EGP</Cell></tr>)}</Table></ListLayout>{(!data.products.length||!data.suppliers.length)&&<p className="mt-4 rounded-xl bg-amber-50 p-4 text-sm text-amber-800">{locale==="ar"?"أضف منتجًا وموردًا أولًا، ثم ارجع لإنشاء إذن الاستلام.":"Add a product and supplier before creating a receipt."}</p>}{open&&<ReceiptModal locale={locale} data={data} close={()=>setOpen(false)} save={receive}/>}</>;
}

function CountsPage({locale,data,setData,toast}:{locale:Locale;data:Data;setData:React.Dispatch<React.SetStateAction<Data>>;toast:(s?:string)=>void}){
  const t=useTranslations();const [open,setOpen]=useState(false);const counts=data.movements.filter(m=>m.type==="Stock Adjustment");
  function post(v:{reference:string;branch:string;product:string;actual:number;note:string}){const balance=data.inventory.find(i=>i.branchId===v.branch&&i.productId===v.product);if(!balance)return;const difference=v.actual-balance.currentQuantity;const date=new Date().toISOString().slice(0,10);setData(d=>{const updated=d.inventory.map(i=>{if(i.id!==balance.id)return i;const available=v.actual-i.reservedQuantity;return {...i,currentQuantity:v.actual,availableQuantity:available,inventoryValue:calculateInventoryValue(v.actual,i.averageCost),lastMovementDate:date,status:getStockStatus(available,i.minimumQuantity,i.maximumQuantity)}});const movement:StockMovement={id:`m-count-${Date.now()}`,date,type:"Stock Adjustment",branchId:v.branch,productId:v.product,quantity:difference,reference:v.reference,user:locale==="ar"?"مسؤول الجرد":"Stock counter",systemQuantity:balance.currentQuantity,actualQuantity:v.actual,note:v.note};return {...d,inventory:updated,movements:[movement,...d.movements]}});setOpen(false);toast(difference===0?(locale==="ar"?"تم اعتماد الجرد بدون فروق":"Count posted with no variance"):(locale==="ar"?"تم اعتماد الجرد وتسوية المخزون":"Count posted and inventory adjusted"))}
  return <><ListLayout title={t("counts")} search="" setSearch={()=>{}} actions={<button disabled={!data.products.length} onClick={()=>setOpen(true)} className="btn-primary"><ClipboardCheck size={17}/>{locale==="ar"?"جرد جديد":"New stock count"}</button>}><Table headers={[locale==="ar"?"رقم الجرد":"Count No.",t("date"),t("branch"),t("product"),locale==="ar"?"رصيد النظام":"System qty",locale==="ar"?"الكمية الفعلية":"Actual qty",locale==="ar"?"الفرق":"Variance",locale==="ar"?"السبب":"Reason"]} empty={!counts.length}>{counts.map(m=><tr key={m.id}><Cell strong>{m.reference}</Cell><Cell>{m.date}</Cell><Cell>{name(data.branches,m.branchId,locale)}</Cell><Cell>{name(data.products,m.productId,locale)}</Cell><Cell>{m.systemQuantity??0}</Cell><Cell>{m.actualQuantity??0}</Cell><Cell><span className={m.quantity===0?"text-emerald-600":m.quantity>0?"text-blue-600":"text-red-600"}>{m.quantity>0?"+":""}{m.quantity}</span></Cell><Cell>{m.note??"—"}</Cell></tr>)}</Table></ListLayout>{!data.products.length&&<p className="mt-4 rounded-xl bg-amber-50 p-4 text-sm text-amber-800">{locale==="ar"?"أضف منتجًا أولًا حتى تتمكن من إجراء الجرد.":"Add a product before starting a stock count."}</p>}{open&&<CountModal locale={locale} data={data} close={()=>setOpen(false)} save={post}/>}</>;
}

function SuppliersPage({locale,data,setData,toast}:{locale:Locale;data:Data;setData:React.Dispatch<React.SetStateAction<Data>>;toast:(s?:string)=>void}){
  const t=useTranslations();const [search,setSearch]=useState("");const [open,setOpen]=useState(false);const rows=data.suppliers.filter(s=>`${s.code} ${s.nameAr} ${s.nameEn} ${s.phone}`.toLowerCase().includes(search.toLowerCase()));
  function add(v:{code:string;nameAr:string;nameEn:string;contact:string;phone:string;email:string}){const supplier:Supplier={id:`s-${Date.now()}`,...v,status:"active"};setData(d=>({...d,suppliers:[supplier,...d.suppliers]}));setOpen(false);toast(locale==="ar"?"تمت إضافة المورد":"Supplier added")}
  function remove(id:string){if(!confirm(locale==="ar"?"هل تريد حذف المورد؟":"Delete this supplier?"))return;setData(d=>({...d,suppliers:d.suppliers.filter(s=>s.id!==id)}));toast(locale==="ar"?"تم حذف المورد":"Supplier deleted")}
  return <><ListLayout title={t("suppliers")} search={search} setSearch={setSearch} actions={<><button onClick={()=>downloadCSV("suppliers.csv",["Code,Arabic name,English name,Contact,Phone,Email",...rows.map(s=>`${s.code},${s.nameAr},${s.nameEn},${s.contact},${s.phone},${s.email}`)])} className="btn-secondary"><FileDown size={17}/>{t("export")}</button><button onClick={()=>setOpen(true)} className="btn-primary"><Plus size={17}/>{t("add")}</button></>}><Table headers={[t("code"),t("name"),locale==="ar"?"مسؤول الاتصال":"Contact person",locale==="ar"?"الهاتف":"Phone",locale==="ar"?"البريد الإلكتروني":"Email",t("status"),t("actions")]} empty={!rows.length}>{rows.map(s=><tr key={s.id}><Cell>{s.code}</Cell><Cell strong>{locale==="ar"?s.nameAr:s.nameEn}</Cell><Cell>{s.contact}</Cell><Cell>{s.phone}</Cell><Cell>{s.email}</Cell><Cell><Status value={s.status}/></Cell><Cell><button onClick={()=>remove(s.id)} className="rounded-lg p-2 text-red-600 hover:bg-red-50"><Trash2 size={17}/></button></Cell></tr>)}</Table></ListLayout>{open&&<SupplierModal locale={locale} count={data.suppliers.length} close={()=>setOpen(false)} save={add}/>}</>;
}

function SupplierModal({locale,count,close,save}:{locale:Locale;count:number;close:()=>void;save:(v:{code:string;nameAr:string;nameEn:string;contact:string;phone:string;email:string})=>void}){
  const [form,setForm]=useState({code:`SUP-${String(count+1).padStart(3,"0")}`,nameAr:"",nameEn:"",contact:"",phone:"",email:""});
  return <div className="fixed inset-0 z-50 grid place-items-center bg-slate-950/50 p-4"><form onSubmit={e=>{e.preventDefault();save(form)}} className="card max-h-[90vh] w-full max-w-xl overflow-y-auto p-6"><div className="flex"><h2 className="text-xl font-bold">{locale==="ar"?"إضافة مورد":"Add supplier"}</h2><button type="button" onClick={close} className="ms-auto"><X/></button></div><div className="mt-6 grid gap-4 sm:grid-cols-2"><Field label={locale==="ar"?"كود المورد":"Supplier code"} value={form.code} set={v=>setForm({...form,code:v})}/><Field label="الاسم بالعربية" value={form.nameAr} set={v=>setForm({...form,nameAr:v})}/><Field label="English name" value={form.nameEn} set={v=>setForm({...form,nameEn:v})}/><Field label={locale==="ar"?"مسؤول الاتصال":"Contact person"} value={form.contact} set={v=>setForm({...form,contact:v})}/><label className="text-sm">{locale==="ar"?"رقم الهاتف":"Phone number"}<input required pattern="[0-9+ -]{7,18}" className="input mt-2" value={form.phone} onChange={e=>setForm({...form,phone:e.target.value})}/></label><label className="text-sm">{locale==="ar"?"البريد الإلكتروني":"Email"}<input required type="email" className="input mt-2" value={form.email} onChange={e=>setForm({...form,email:e.target.value})}/></label></div><div className="mt-6 flex justify-end gap-2"><button type="button" onClick={close} className="btn-secondary">{locale==="ar"?"إلغاء":"Cancel"}</button><button className="btn-primary">{locale==="ar"?"حفظ المورد":"Save supplier"}</button></div></form></div>;
}

function CountModal({locale,data,close,save}:{locale:Locale;data:Data;close:()=>void;save:(v:{reference:string;branch:string;product:string;actual:number;note:string})=>void}){
  const [form,setForm]=useState({reference:`SC-${String(data.movements.filter(m=>m.type==="Stock Adjustment").length+1).padStart(6,"0")}`,branch:data.branches[0]?.id??"",product:data.products[0]?.id??"",actual:0,note:""});const balance=data.inventory.find(i=>i.branchId===form.branch&&i.productId===form.product);const system=balance?.currentQuantity??0;const difference=form.actual-system;
  return <div className="fixed inset-0 z-50 grid place-items-center bg-slate-950/50 p-4"><form onSubmit={e=>{e.preventDefault();save(form)}} className="card max-h-[90vh] w-full max-w-xl overflow-y-auto p-6"><div className="flex"><h2 className="text-xl font-bold">{locale==="ar"?"جرد وتسوية المخزون":"Stock count & adjustment"}</h2><button type="button" onClick={close} className="ms-auto"><X/></button></div><div className="mt-6 grid gap-4 sm:grid-cols-2"><Field label={locale==="ar"?"رقم الجرد":"Count number"} value={form.reference} set={v=>setForm({...form,reference:v})}/><SelectField label={locale==="ar"?"الفرع":"Branch"} value={form.branch} set={v=>setForm({...form,branch:v})} items={data.branches.map(b=>({id:b.id,label:locale==="ar"?b.nameAr:b.nameEn}))}/><label className="text-sm sm:col-span-2">{locale==="ar"?"المنتج":"Product"}<select className="input mt-2" value={form.product} onChange={e=>setForm({...form,product:e.target.value})}>{data.products.map(p=><option key={p.id} value={p.id}>{locale==="ar"?p.nameAr:p.nameEn}</option>)}</select></label><div className="rounded-xl bg-slate-100 p-4 text-sm dark:bg-slate-800"><span className="text-slate-500">{locale==="ar"?"رصيد النظام":"System quantity"}</span><strong className="mt-1 block text-2xl">{system}</strong></div><label className="text-sm">{locale==="ar"?"الكمية الفعلية":"Actual quantity"}<input required min="0" type="number" className="input mt-2" value={form.actual} onChange={e=>setForm({...form,actual:Number(e.target.value)})}/></label><label className="text-sm sm:col-span-2">{locale==="ar"?"سبب فرق الجرد":"Variance reason"}<input required={difference!==0} className="input mt-2" placeholder={locale==="ar"?"مثال: تلف أو عجز أو زيادة":"e.g. damage, shortage or surplus"} value={form.note} onChange={e=>setForm({...form,note:e.target.value})}/></label></div><div className={`mt-4 rounded-xl p-4 text-sm ${difference===0?"bg-emerald-50 text-emerald-700":difference>0?"bg-blue-50 text-blue-700":"bg-red-50 text-red-700"}`}>{locale==="ar"?"فرق الجرد":"Variance"}: <strong>{difference>0?"+":""}{difference}</strong></div><div className="mt-6 flex justify-end gap-2"><button type="button" onClick={close} className="btn-secondary">{locale==="ar"?"إلغاء":"Cancel"}</button><button className="btn-primary">{locale==="ar"?"اعتماد الجرد والتسوية":"Post count & adjustment"}</button></div></form></div>;
}

function ReceiptModal({locale,data,close,save}:{locale:Locale;data:Data;close:()=>void;save:(v:{reference:string;supplier:string;branch:string;product:string;quantity:number;cost:number})=>void}){
  const [form,setForm]=useState({reference:`PR-${String(data.movements.filter(m=>m.type==="Purchase Receipt").length+1).padStart(6,"0")}`,supplier:data.suppliers[0]?(locale==="ar"?data.suppliers[0].nameAr:data.suppliers[0].nameEn):"",branch:data.branches[0]?.id??"",product:data.products[0]?.id??"",quantity:1,cost:data.products[0]?.purchasePrice??0});
  return <div className="fixed inset-0 z-50 grid place-items-center bg-slate-950/50 p-4"><form onSubmit={e=>{e.preventDefault();save(form)}} className="card max-h-[90vh] w-full max-w-xl overflow-y-auto p-6"><div className="flex"><h2 className="text-xl font-bold">{locale==="ar"?"إذن استلام مشتريات":"Purchase receipt"}</h2><button type="button" onClick={close} className="ms-auto"><X/></button></div><div className="mt-6 grid gap-4 sm:grid-cols-2"><Field label={locale==="ar"?"رقم الإذن":"Receipt number"} value={form.reference} set={v=>setForm({...form,reference:v})}/><label className="text-sm">{locale==="ar"?"المورد":"Supplier"}<select className="input mt-2" value={form.supplier} onChange={e=>setForm({...form,supplier:e.target.value})}>{data.suppliers.map(s=><option key={s.id} value={locale==="ar"?s.nameAr:s.nameEn}>{locale==="ar"?s.nameAr:s.nameEn}</option>)}</select></label><SelectField label={locale==="ar"?"الفرع المستلم":"Receiving branch"} value={form.branch} set={v=>setForm({...form,branch:v})} items={data.branches.map(b=>({id:b.id,label:locale==="ar"?b.nameAr:b.nameEn}))}/><label className="text-sm">{locale==="ar"?"المنتج":"Product"}<select className="input mt-2" value={form.product} onChange={e=>{const p=data.products.find(p=>p.id===e.target.value);setForm({...form,product:e.target.value,cost:p?.purchasePrice??form.cost})}}>{data.products.map(p=><option key={p.id} value={p.id}>{locale==="ar"?p.nameAr:p.nameEn}</option>)}</select></label><label className="text-sm">{locale==="ar"?"الكمية المستلمة":"Received quantity"}<input required min="1" type="number" className="input mt-2" value={form.quantity} onChange={e=>setForm({...form,quantity:Number(e.target.value)})}/></label><label className="text-sm">{locale==="ar"?"سعر شراء الوحدة":"Unit purchase cost"}<input required min="0.01" step="0.01" type="number" className="input mt-2" value={form.cost||""} onChange={e=>setForm({...form,cost:Number(e.target.value)})}/></label></div><div className="mt-4 rounded-xl bg-brand-50 p-4 text-sm text-brand-700">{locale==="ar"?"إجمالي الإذن":"Receipt total"}: <strong>{(form.quantity*form.cost).toLocaleString()} EGP</strong></div><div className="mt-6 flex justify-end gap-2"><button type="button" onClick={close} className="btn-secondary">{locale==="ar"?"إلغاء":"Cancel"}</button><button className="btn-primary">{locale==="ar"?"تأكيد الاستلام":"Confirm receipt"}</button></div></form></div>;
}

function TransferModal({locale,data,error,close,save}:{locale:Locale;data:Data;error:string;close:()=>void;save:(v:{from:string;to:string;product:string;quantity:number})=>void}){const [form,setForm]=useState({from:data.branches[0]?.id??"",to:data.branches[1]?.id??"",product:data.products[0]?.id??"",quantity:1});const source=data.inventory.find(i=>i.branchId===form.from&&i.productId===form.product);return <div className="fixed inset-0 z-50 grid place-items-center bg-slate-950/50 p-4"><form onSubmit={e=>{e.preventDefault();save(form)}} className="card w-full max-w-xl p-6"><div className="flex"><h2 className="text-xl font-bold">{locale==="ar"?"تحويل بين الفروع":"Branch transfer"}</h2><button type="button" onClick={close} className="ms-auto"><X/></button></div><div className="mt-6 grid gap-4 sm:grid-cols-2"><SelectField label={locale==="ar"?"من فرع":"From branch"} value={form.from} set={v=>setForm({...form,from:v})} items={data.branches.map(b=>({id:b.id,label:locale==="ar"?b.nameAr:b.nameEn}))}/><SelectField label={locale==="ar"?"إلى فرع":"To branch"} value={form.to} set={v=>setForm({...form,to:v})} items={data.branches.map(b=>({id:b.id,label:locale==="ar"?b.nameAr:b.nameEn}))}/><label className="text-sm sm:col-span-2">{locale==="ar"?"المنتج":"Product"}<select className="input mt-2" value={form.product} onChange={e=>setForm({...form,product:e.target.value})}>{data.products.map(p=><option key={p.id} value={p.id}>{locale==="ar"?p.nameAr:p.nameEn}</option>)}</select></label><label className="text-sm sm:col-span-2">{locale==="ar"?"الكمية":"Quantity"}<input required min="1" max={source?.availableQuantity??0} type="number" className="input mt-2" value={form.quantity} onChange={e=>setForm({...form,quantity:Number(e.target.value)})}/><small className="mt-1 block text-slate-500">{locale==="ar"?"المتاح":"Available"}: {source?.availableQuantity??0}</small></label></div>{error&&<p className="mt-4 text-sm text-red-600">{error}</p>}<div className="mt-6 flex justify-end gap-2"><button type="button" onClick={close} className="btn-secondary">{locale==="ar"?"إلغاء":"Cancel"}</button><button className="btn-primary">{locale==="ar"?"تنفيذ التحويل":"Complete transfer"}</button></div></form></div>}
function SelectField({label,value,set,items}:{label:string;value:string;set:(v:string)=>void;items:{id:string;label:string}[]}){return <label className="text-sm">{label}<select className="input mt-2" value={value} onChange={e=>set(e.target.value)}>{items.map(i=><option key={i.id} value={i.id}>{i.label}</option>)}</select></label>}

function Dashboard({locale,data}:{locale:Locale;data:Data}){
  const t=useTranslations();const total=data.inventory.reduce((s,x)=>s+x.inventoryValue,0);const alerts=data.inventory.filter(x=>x.status!=="available").length;
  const byBranch=data.branches.map(b=>({name:locale==="ar"?b.nameAr:b.nameEn,value:data.inventory.filter(i=>i.branchId===b.id).reduce((s,i)=>s+i.inventoryValue,0)}));const max=Math.max(...byBranch.map(x=>x.value),1);
  const cards:{label:string;value:string|number;Icon:LucideIcon;color:string}[]=[{label:t("totalProducts"),value:data.products.length,Icon:Package,color:"bg-blue-100 text-blue-700"},{label:t("totalBranches"),value:data.branches.filter(b=>b.status==="active").length,Icon:Building2,color:"bg-emerald-100 text-emerald-700"},{label:t("inventoryValue"),value:`${Math.round(total/1000).toLocaleString()}K EGP`,Icon:ShoppingCart,color:"bg-violet-100 text-violet-700"},{label:t("lowStock"),value:alerts,Icon:Bell,color:"bg-amber-100 text-amber-700"}];
  return <div className="space-y-6"><div className="grid gap-4 sm:grid-cols-2 xl:grid-cols-4">{cards.map(({label,value,Icon,color})=><div className="card p-5" key={label}><div className="flex items-start justify-between"><div><p className="text-sm text-slate-500">{label}</p><strong className="mt-2 block text-2xl">{value}</strong></div><span className={`rounded-xl p-3 ${color}`}><Icon size={22}/></span></div></div>)}</div><div className="grid gap-6 xl:grid-cols-5"><section className="card p-5 xl:col-span-3"><h2 className="font-bold">{t("stockByBranch")}</h2><div className="mt-7 flex h-64 items-end gap-4">{byBranch.map(x=><div key={x.name} className="flex h-full flex-1 flex-col justify-end text-center"><span className="mb-2 text-xs font-semibold">{Math.round(x.value/1000)}K</span><div className="mx-auto w-full max-w-14 rounded-t-lg bg-brand-500" style={{height:`${Math.max(8,x.value/max*85)}%`}}/><small className="mt-2 truncate text-slate-500">{x.name}</small></div>)}</div></section><section className="card p-5 xl:col-span-2"><h2 className="font-bold">{t("recentMovements")}</h2><div className="mt-4 space-y-3">{data.movements.slice(0,5).map(m=><div key={m.id} className="flex items-center gap-3 rounded-xl bg-slate-50 p-3 dark:bg-slate-800"><span className="rounded-lg bg-brand-100 p-2 text-brand-700"><Activity size={17}/></span><div className="min-w-0 flex-1"><p className="truncate text-sm font-semibold">{m.type} · {m.reference}</p><small className="text-slate-500">{m.date}</small></div><b className="text-sm">{m.quantity}</b></div>)}</div></section></div><section className="card overflow-hidden"><div className="border-b border-slate-200 p-5 dark:border-slate-800"><h2 className="font-bold">{locale==="ar"?"آخر السلع المضافة وأسعارها":"Recently added products and prices"}</h2></div><Table headers={[locale==="ar"?"السلعة":"Product","SKU",locale==="ar"?"سعر الشراء":"Purchase price",locale==="ar"?"تاريخ الإضافة":"Added date"]} empty={!data.products.length}>{data.products.slice(0,8).map(p=><tr key={p.id}><Cell strong>{locale==="ar"?p.nameAr:p.nameEn}</Cell><Cell>{p.sku}</Cell><Cell>{p.purchasePrice.toLocaleString()} EGP</Cell><Cell>{p.createdAt}</Cell></tr>)}</Table></section></div>
}

function InventoryPage({locale,data}:{locale:Locale;data:Data}){
  const t=useTranslations();const [search,setSearch]=useState("");const [branch,setBranch]=useState("all");const [page,setPage]=useState(1);const [pageSize,setPageSize]=useState(20);
  const rows=data.inventory.filter(i=>branch==="all"||i.branchId===branch).filter(i=>{const p=data.products.find(p=>p.id===i.productId);return `${p?.nameAr} ${p?.nameEn} ${p?.sku}`.toLowerCase().includes(search.toLowerCase())});
  const pageCount=Math.max(1,Math.ceil(rows.length/pageSize));const pageRows=rows.slice((page-1)*pageSize,page*pageSize);const first=rows.length?(page-1)*pageSize+1:0;const last=Math.min(page*pageSize,rows.length);
  useEffect(()=>setPage(1),[search,branch,pageSize]);useEffect(()=>{if(page>pageCount)setPage(pageCount)},[page,pageCount]);
  function csv(){downloadCSV("inventory.csv",["Product,SKU,Branch,Current,Reserved,Available,Value",...rows.map(i=>{const p=data.products.find(p=>p.id===i.productId);const b=data.branches.find(b=>b.id===i.branchId);return `${p?.nameEn},${p?.sku},${b?.nameEn},${i.currentQuantity},${i.reservedQuantity},${i.availableQuantity},${i.inventoryValue}`})])}
  return <ListLayout title={t("inventory")} search={search} setSearch={setSearch} actions={<><button onClick={csv} className="btn-secondary"><FileDown size={17}/>{t("export")}</button><button onClick={()=>window.print()} className="btn-secondary"><Printer size={17}/>{t("print")}</button></>} filters={<><select className="input w-auto" value={branch} onChange={e=>setBranch(e.target.value)}><option value="all">{t("all")}</option>{data.branches.map(b=><option key={b.id} value={b.id}>{locale==="ar"?b.nameAr:b.nameEn}</option>)}</select><select aria-label={locale==="ar"?"عدد الصفوف":"Rows per page"} className="input w-auto" value={pageSize} onChange={e=>setPageSize(Number(e.target.value))}>{[10,20,50].map(n=><option key={n} value={n}>{n} {locale==="ar"?"في الصفحة":"per page"}</option>)}</select></>}><Table headers={[t("product"),"SKU",t("branch"),t("quantity"),t("available"),t("status"),t("value")]} empty={!rows.length}>{pageRows.map(i=>{const p=data.products.find(p=>p.id===i.productId);const b=data.branches.find(b=>b.id===i.branchId);return <tr key={i.id}><Cell strong>{p?<div className="flex items-center gap-3"><ProductImage product={p}/><span>{locale==="ar"?p.nameAr:p.nameEn}</span></div>:"—"}</Cell><Cell>{p?.sku}</Cell><Cell>{locale==="ar"?b?.nameAr:b?.nameEn}</Cell><Cell>{i.currentQuantity}</Cell><Cell>{i.availableQuantity} {locale==="ar"?p?.unitNameAr:p?.unitNameEn}</Cell><Cell><Status value={i.status}/></Cell><Cell>{i.inventoryValue.toLocaleString()} EGP</Cell></tr>})}</Table>{rows.length>0&&<div className="no-print flex flex-wrap items-center gap-2 border-t border-slate-200 p-4 dark:border-slate-800"><span className="me-auto text-sm text-slate-500">{locale==="ar"?`عرض ${first}–${last} من ${rows.length}`:`Showing ${first}–${last} of ${rows.length}`}</span><button disabled={page===1} onClick={()=>setPage(p=>p-1)} className="btn-secondary px-3 py-2">{locale==="ar"?"السابق":"Previous"}</button><div className="flex flex-wrap gap-1">{Array.from({length:pageCount},(_,i)=>i+1).map(n=><button key={n} onClick={()=>setPage(n)} aria-current={page===n?"page":undefined} className={`h-9 min-w-9 rounded-lg px-2 text-sm font-bold ${page===n?"bg-brand-600 text-white":"border border-slate-200 hover:bg-slate-50 dark:border-slate-700"}`}>{n}</button>)}</div><button disabled={page===pageCount} onClick={()=>setPage(p=>p+1)} className="btn-secondary px-3 py-2">{locale==="ar"?"التالي":"Next"}</button></div>}</ListLayout>
}

function GenericPage({section,locale,data,setData,toast}:{section:string;locale:Locale;data:Data;setData:React.Dispatch<React.SetStateAction<Data>>;toast:(s?:string)=>void}){const t=useTranslations();const [search,setSearch]=useState("");const [modal,setModal]=useState(false);let headers:string[]=[];let rows:React.ReactNode[]=[];
  if(section==="branches"){headers=[t("code"),t("name"),locale==="ar"?"المحافظة":"Governorate",locale==="ar"?"المدير":"Manager",t("status"),t("actions")];rows=data.branches.filter(b=>`${b.nameAr} ${b.nameEn} ${b.code}`.toLowerCase().includes(search.toLowerCase())).map(b=><tr key={b.id}><Cell>{b.code}</Cell><Cell strong>{locale==="ar"?b.nameAr:b.nameEn}</Cell><Cell>{locale==="ar"?b.governorateAr:b.governorateEn}</Cell><Cell>{b.managerName}</Cell><Cell><Status value={b.status}/></Cell><Cell><MoreHorizontal/></Cell></tr>)}
  else if(section==="products"){headers=["SKU",t("name"),locale==="ar"?"التصنيف":"Category",locale==="ar"?"الوحدة":"Unit",locale==="ar"?"سعر الشراء":"Purchase price",t("status"),t("actions")];rows=data.products.filter(p=>`${p.nameAr} ${p.nameEn} ${p.sku}`.toLowerCase().includes(search.toLowerCase())).map(p=><tr key={p.id}><Cell>{p.sku}</Cell><Cell strong>{locale==="ar"?p.nameAr:p.nameEn}</Cell><Cell>{locale==="ar"?p.categoryNameAr:p.categoryNameEn}</Cell><Cell>{locale==="ar"?p.unitNameAr:p.unitNameEn}</Cell><Cell>{p.purchasePrice} EGP</Cell><Cell><Status value={p.status}/></Cell><Cell><MoreHorizontal/></Cell></tr>)}
  else if(section==="suppliers"){headers=[t("code"),t("name"),locale==="ar"?"مسؤول الاتصال":"Contact",locale==="ar"?"الهاتف":"Phone",t("status")];rows=data.suppliers.filter(s=>`${s.nameAr} ${s.nameEn} ${s.code}`.toLowerCase().includes(search.toLowerCase())).map(s=><tr key={s.id}><Cell>{s.code}</Cell><Cell strong>{locale==="ar"?s.nameAr:s.nameEn}</Cell><Cell>{s.contact}</Cell><Cell>{s.phone}</Cell><Cell><Status value={s.status}/></Cell></tr>)}
  else if(section==="movements"||section==="audit"){headers=[locale==="ar"?"المرجع":"Reference",t("date"),locale==="ar"?"النوع":"Type",t("branch"),t("product"),t("quantity"),locale==="ar"?"المستخدم":"User"];rows=data.movements.filter(m=>`${m.reference} ${m.type}`.toLowerCase().includes(search.toLowerCase())).map(m=><tr key={m.id}><Cell strong>{m.reference}</Cell><Cell>{m.date}</Cell><Cell>{m.type}</Cell><Cell>{name(data.branches,m.branchId,locale)}</Cell><Cell>{name(data.products,m.productId,locale)}</Cell><Cell>{m.quantity}</Cell><Cell>{m.user}</Cell></tr>)}
  else if(section==="transfers"){headers=[locale==="ar"?"رقم التحويل":"Transfer No.",t("date"),locale==="ar"?"من":"From",locale==="ar"?"إلى":"To",locale==="ar"?"الأصناف":"Items",t("status")];rows=data.transfers.map(x=><tr key={x.id}><Cell strong>{x.number}</Cell><Cell>{x.date}</Cell><Cell>{name(data.branches,x.fromBranchId,locale)}</Cell><Cell>{name(data.branches,x.toBranchId,locale)}</Cell><Cell>{x.items}</Cell><Cell><Status value={x.status}/></Cell></tr>)}
  else if(section==="users"){headers=[t("name"),t("email"),locale==="ar"?"الدور":"Role",t("branch"),t("status")];rows=data.users.map(u=><tr key={u.id}><Cell strong>{u.name}</Cell><Cell>{u.email}</Cell><Cell>{u.role}</Cell><Cell>{name(data.branches,u.branchId,locale)}</Cell><Cell><Status value={u.status}/></Cell></tr>)}
  else {const isReceipt=section==="receipts";headers=[locale==="ar"?"رقم المستند":"Document No.",t("date"),isReceipt?t("suppliers"):t("branch"),locale==="ar"?"عدد الأصناف":"Items",t("status")];rows=Array.from({length:5},(_,i)=><tr key={i}><Cell strong>{isReceipt?`PR-20260${i+1}`:`SC-20260${i+1}`}</Cell><Cell>2026-07-{10+i}</Cell><Cell>{isReceipt?(locale==="ar"?data.suppliers[i%data.suppliers.length]?.nameAr:data.suppliers[i%data.suppliers.length]?.nameEn):name(data.branches,`b${i+1}`,locale)}</Cell><Cell>{2+i}</Cell><Cell><Status value={i%2?"draft":"received"}/></Cell></tr>)}
  function add(nameValue:string){if(section==="branches"){const b={...data.branches[0],id:`b${Date.now()}`,code:`NEW-${data.branches.length+1}`,nameAr:nameValue,nameEn:nameValue,managerName:"—"};setData(d=>({...d,branches:[...d.branches,b]}))}toast();setModal(false)}
  return <><ListLayout title={t(nav.find(n=>n[0]===section)?.[1]??"products")} search={search} setSearch={setSearch} actions={<><button onClick={()=>downloadCSV(`${section}.csv`,[headers.join(",")])} className="btn-secondary"><FileDown size={17}/>{t("export")}</button><button onClick={()=>setModal(true)} className="btn-primary"><Plus size={17}/>{t("add")}</button></>}><Table headers={headers} empty={!rows.length}>{rows}</Table></ListLayout>{modal&&<SimpleModal locale={locale} title={t("add")} close={()=>setModal(false)} save={add}/>}</>}

function Reports({locale,data}:{locale:Locale;data:Data}){
  type Period="daily"|"weekly"|"monthly"|"custom";const iso=(d:Date)=>d.toISOString().slice(0,10);const today=iso(new Date());const monthStart=`${today.slice(0,7)}-01`;const [period,setPeriod]=useState<Period>("monthly");const [branch,setBranch]=useState("all");const [customFrom,setCustomFrom]=useState(monthStart);const [customTo,setCustomTo]=useState(today);const [whatsappOpen,setWhatsappOpen]=useState(false);
  const ago=new Date();ago.setDate(ago.getDate()-6);const range=period==="daily"?{from:today,to:today}:period==="weekly"?{from:iso(ago),to:today}:period==="monthly"?{from:monthStart,to:today}:{from:customFrom,to:customTo};
  const movements=data.movements.filter(m=>m.date>=range.from&&m.date<=range.to&&(branch==="all"||m.branchId===branch));const inventory=data.inventory.filter(i=>branch==="all"||i.branchId===branch);const incoming=movements.filter(m=>m.quantity>0).reduce((s,m)=>s+m.quantity,0);const outgoing=Math.abs(movements.filter(m=>m.quantity<0).reduce((s,m)=>s+m.quantity,0));const value=inventory.reduce((s,i)=>s+i.inventoryValue,0);const low=inventory.filter(i=>i.status==="low"||i.status==="out").length;
  const byDate=new Map<string,{date:string;incoming:number;outgoing:number}>();for(const m of movements){const row=byDate.get(m.date)??{date:m.date,incoming:0,outgoing:0};if(m.quantity>=0)row.incoming+=m.quantity;else row.outgoing+=Math.abs(m.quantity);byDate.set(m.date,row)}const chartData=[...byDate.values()].sort((a,b)=>a.date.localeCompare(b.date));
  const byProduct=new Map<string,number>();for(const m of movements.filter(x=>x.quantity<0))byProduct.set(m.productId,(byProduct.get(m.productId)??0)+Math.abs(m.quantity));const topOutgoingProducts=[...byProduct.entries()].map(([id,quantity])=>({id,name:name(data.products,id,locale),quantity})).sort((a,b)=>b.quantity-a.quantity).slice(0,6);const maxOutgoingProduct=Math.max(1,...topOutgoingProducts.map(x=>x.quantity));
  const packageDemand=new Map<string,{quantity:number;orders:number}>();for(const issue of data.packageIssues.filter(x=>x.status==="posted"&&x.date>=range.from&&x.date<=range.to&&(branch==="all"||x.branchId===branch))){const current=packageDemand.get(issue.packageId)??{quantity:0,orders:0};current.quantity+=issue.packageQuantity;current.orders+=1;packageDemand.set(issue.packageId,current)}const topPackages=[...packageDemand.entries()].map(([id,totals])=>{const pkg=data.packages.find(x=>x.id===id);return {id,name:pkg?(locale==="ar"?pkg.nameAr:pkg.nameEn):"—",...totals}}).sort((a,b)=>b.quantity-a.quantity).slice(0,6);const maxPackage=Math.max(1,...topPackages.map(x=>x.quantity));
  const periods:[Period,string][]=[["daily",locale==="ar"?"يومي":"Daily"],["weekly",locale==="ar"?"أسبوعي":"Weekly"],["monthly",locale==="ar"?"شهري":"Monthly"],["custom",locale==="ar"?"من تاريخ إلى تاريخ":"Custom range"]];
  function exportReport(){void downloadExcel(`inventory-report-${range.from}-${range.to}.xlsx`,[locale==="ar"?"التاريخ":"Date",locale==="ar"?"المرجع":"Reference",locale==="ar"?"نوع الحركة":"Movement type",locale==="ar"?"الفرع":"Branch",locale==="ar"?"المنتج":"Product",locale==="ar"?"الكمية":"Quantity",locale==="ar"?"المستخدم":"User"],movements.map(m=>[m.date,m.reference,m.type,name(data.branches,m.branchId,locale),name(data.products,m.productId,locale),m.quantity,m.user]))}
  return <><div className="report-print space-y-5"><div className="print-only report-print-header"><h1>{locale==="ar"?"تقرير حركة المخزون":"Inventory Movement Report"}</h1><p>{range.from} — {range.to} · {branch==="all"?(locale==="ar"?"كل فروع الشركة":"All company branches"):name(data.branches,branch,locale)}</p></div><section className="report-controls card p-4 sm:p-5"><div className="flex flex-wrap gap-2">{periods.map(([id,label])=><button key={id} onClick={()=>setPeriod(id)} className={`rounded-xl px-4 py-2 text-sm font-bold ${period===id?"bg-brand-600 text-white":"bg-slate-100 text-slate-700 dark:bg-slate-800 dark:text-slate-200"}`}>{label}</button>)}</div><div className="mt-4 grid gap-3 md:grid-cols-3"><label className="text-sm">{locale==="ar"?"الفرع / المخزن":"Branch / warehouse"}<select className="input mt-2" value={branch} onChange={e=>setBranch(e.target.value)}><option value="all">{locale==="ar"?"كل فروع الشركة":"All company branches"}</option>{data.branches.map(b=><option key={b.id} value={b.id}>{locale==="ar"?b.nameAr:b.nameEn}</option>)}</select></label>{period==="custom"&&<><label className="text-sm">{locale==="ar"?"من تاريخ":"From"}<input type="date" className="input mt-2" value={customFrom} onChange={e=>setCustomFrom(e.target.value)}/></label><label className="text-sm">{locale==="ar"?"إلى تاريخ":"To"}<input type="date" className="input mt-2" value={customTo} onChange={e=>setCustomTo(e.target.value)}/></label></>}</div><div className="mt-4 flex flex-wrap items-center gap-2 text-sm text-slate-500"><span>{locale==="ar"?`الفترة: ${range.from} إلى ${range.to}`:`Period: ${range.from} to ${range.to}`}</span><div className="no-print ms-auto flex gap-2"><button onClick={exportReport} disabled={!movements.length} className="btn-primary"><FileDown size={17}/>{locale==="ar"?"حفظ Excel":"Save Excel"}</button><button onClick={()=>window.print()} className="btn-secondary"><Printer size={17}/>{locale==="ar"?"طباعة التقرير":"Print report"}</button><button onClick={()=>setWhatsappOpen(true)} disabled={!movements.length} className="btn-secondary text-emerald-700"><MessageCircle size={17}/>{locale==="ar"?"إرسال التقرير واتساب":"Send report via WhatsApp"}</button></div></div></section><div className="report-summary grid gap-4 sm:grid-cols-2 xl:grid-cols-4">{[{title:locale==="ar"?"الوارد":"Stock in",value:incoming,color:"text-emerald-600"},{title:locale==="ar"?"الصادر":"Stock out",value:outgoing,color:"text-red-600"},{title:locale==="ar"?"قيمة المخزون الحالية":"Current stock value",value:`${value.toLocaleString()} EGP`,color:"text-brand-700"},{title:locale==="ar"?"منخفض / نافد":"Low / out of stock",value:low,color:"text-amber-600"}].map(card=><section className="card p-5" key={card.title}><p className="text-sm text-slate-500">{card.title}</p><strong className={`mt-2 block text-2xl ${card.color}`}>{card.value}</strong></section>)}</div><div className="report-chart-grid grid gap-5 xl:grid-cols-[2fr_1fr]"><section className="report-chart-card card p-5"><div className="flex flex-wrap items-center gap-3"><span className="grid h-11 w-11 place-items-center rounded-xl bg-brand-50 text-brand-700"><BarChart3 size={22}/></span><div><h2 className="font-bold">{locale==="ar"?"حركة الوارد والصادر":"Incoming and outgoing movement"}</h2><p className="text-xs text-slate-500">{locale==="ar"?`مقارنة الكميات من ${range.from} إلى ${range.to}`:`Quantity comparison from ${range.from} to ${range.to}`}</p></div><div className="ms-auto flex gap-2 text-xs"><span className="rounded-full bg-emerald-50 px-3 py-1.5 font-bold text-emerald-700">{locale==="ar"?"إجمالي الوارد":"Incoming"}: {incoming}</span><span className="rounded-full bg-orange-50 px-3 py-1.5 font-bold text-orange-700">{locale==="ar"?"إجمالي الصادر":"Outgoing"}: {outgoing}</span></div></div><div className="report-chart mt-5 h-80 rounded-2xl bg-gradient-to-b from-slate-50 to-white p-3 dark:from-slate-800/70 dark:to-slate-900">{chartData.length?<ResponsiveContainer width="100%" height="100%"><BarChart data={chartData} margin={{top:18,right:10,left:0,bottom:4}} barGap={6} barCategoryGap="28%"><defs><linearGradient id="incomingGradient" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stopColor="#10b981"/><stop offset="100%" stopColor="#6ee7b7"/></linearGradient><linearGradient id="outgoingGradient" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stopColor="#f97316"/><stop offset="100%" stopColor="#fdba74"/></linearGradient></defs><CartesianGrid vertical={false} stroke="#dbe4ee" strokeDasharray="4 6"/><XAxis dataKey="date" fontSize={11} tickLine={false} axisLine={false} tickFormatter={value=>String(value).slice(5)}/><YAxis fontSize={11} allowDecimals={false} tickLine={false} axisLine={false} width={40}/><Tooltip cursor={{fill:"#e2e8f0",opacity:.45}} contentStyle={{borderRadius:14,border:"1px solid #dbe4ee",boxShadow:"0 12px 30px rgba(15,23,42,.12)"}}/><Legend iconType="circle" iconSize={9} wrapperStyle={{paddingTop:12,fontSize:12}}/><Bar dataKey="incoming" name={locale==="ar"?"وارد":"Incoming"} fill="url(#incomingGradient)" maxBarSize={42} radius={[9,9,2,2]}/><Bar dataKey="outgoing" name={locale==="ar"?"صادر":"Outgoing"} fill="url(#outgoingGradient)" maxBarSize={42} radius={[9,9,2,2]}/></BarChart></ResponsiveContainer>:<div className="grid h-full place-items-center text-slate-500">{locale==="ar"?"لا توجد حركات في الفترة المحددة":"No movements in the selected period"}</div>}</div></section><section className="report-top-products card p-5"><h2 className="font-bold">{locale==="ar"?"أكثر الأصناف خروجًا":"Top outgoing products"}</h2><p className="mt-1 text-xs text-slate-500">{locale==="ar"?"ترتيب حسب إجمالي الكميات التي خرجت من المخزون":"Ranked by total quantity issued from stock"}</p><div className="mt-5 space-y-4">{topOutgoingProducts.length?topOutgoingProducts.map((p,index)=><div key={p.id} className="rounded-xl border border-slate-100 p-3 dark:border-slate-800"><div className="mb-2 flex items-center gap-2 text-sm"><span className="grid h-7 w-7 place-items-center rounded-lg bg-brand-50 text-xs font-bold text-brand-700">{index+1}</span><span className="min-w-0 flex-1 truncate font-semibold">{p.name}</span><b className="rounded-lg bg-slate-100 px-2 py-1 text-xs dark:bg-slate-800">{p.quantity}</b></div><div className="h-2.5 overflow-hidden rounded-full bg-slate-100 dark:bg-slate-800"><div className="h-full rounded-full bg-gradient-to-l from-brand-600 to-emerald-400" style={{width:`${p.quantity/maxOutgoingProduct*100}%`}}/></div></div>):<p className="text-sm text-slate-500">{locale==="ar"?"لا توجد بيانات":"No data"}</p>}</div></section></div><section className="report-package-ranking card p-5"><div className="flex items-center gap-3"><span className="grid h-11 w-11 place-items-center rounded-xl bg-violet-50 text-violet-700"><Package size={22}/></span><div><h2 className="font-bold">{locale==="ar"?"أكثر الباكيدجات طلبًا وتنفيذًا":"Most requested packages"}</h2><p className="text-xs text-slate-500">{locale==="ar"?"محسوب بعدد الباكيدجات الخارجة وعدد عمليات التنفيذ":"Based on issued package quantity and execution count"}</p></div></div><div className="mt-5 grid gap-3 sm:grid-cols-2 xl:grid-cols-3">{topPackages.length?topPackages.map((pkg,index)=><article key={pkg.id} className="rounded-2xl border border-slate-200 p-4 dark:border-slate-800"><div className="flex items-center gap-3"><span className="grid h-9 w-9 place-items-center rounded-xl bg-violet-100 text-sm font-bold text-violet-700">{index+1}</span><div className="min-w-0 flex-1"><h3 className="truncate font-bold">{pkg.name}</h3><p className="text-xs text-slate-500">{pkg.orders} {locale==="ar"?"عملية تنفيذ":"executions"}</p></div><strong className="rounded-xl bg-violet-50 px-3 py-2 text-violet-700">{pkg.quantity} {locale==="ar"?"باكيدج":"packages"}</strong></div><div className="mt-3 h-2.5 overflow-hidden rounded-full bg-slate-100 dark:bg-slate-800"><div className="h-full rounded-full bg-gradient-to-l from-violet-600 to-fuchsia-400" style={{width:`${pkg.quantity/maxPackage*100}%`}}/></div></article>):<p className="text-sm text-slate-500">{locale==="ar"?"لا توجد باكيدجات منفذة في الفترة المحددة":"No packages executed in the selected period"}</p>}</div></section><section className="report-table card overflow-hidden"><div className="border-b border-slate-200 p-4 dark:border-slate-800"><h2 className="font-bold">{locale==="ar"?`تفاصيل الحركات (${movements.length})`:`Movement details (${movements.length})`}</h2></div><Table headers={[locale==="ar"?"التاريخ":"Date",locale==="ar"?"المرجع":"Reference",locale==="ar"?"النوع":"Type",locale==="ar"?"الفرع":"Branch",locale==="ar"?"المنتج":"Product",locale==="ar"?"الكمية":"Quantity",locale==="ar"?"المستخدم":"User"]} empty={!movements.length}>{movements.slice(0,100).map(m=><tr key={m.id}><Cell>{m.date}</Cell><Cell strong>{m.reference}</Cell><Cell>{m.type}</Cell><Cell>{name(data.branches,m.branchId,locale)}</Cell><Cell>{name(data.products,m.productId,locale)}</Cell><Cell><span className={m.quantity>=0?"font-bold text-emerald-600":"font-bold text-red-600"}>{m.quantity>0?"+":""}{m.quantity}</span></Cell><Cell>{m.user}</Cell></tr>)}</Table></section></div>{whatsappOpen&&<WhatsAppReportModal locale={locale} range={range} branchName={branch==="all"?(locale==="ar"?"كل فروع الشركة":"All company branches"):name(data.branches,branch,locale)} stats={{incoming,outgoing,value,low}} chartData={chartData} movements={movements} topOutgoingProducts={topOutgoingProducts} topPackages={topPackages} data={data} close={()=>setWhatsappOpen(false)}/>}</>
}
function WhatsAppReportModal({locale,range,branchName,stats,chartData,movements,topOutgoingProducts,topPackages,data,close}:{locale:Locale;range:{from:string;to:string};branchName:string;stats:{incoming:number;outgoing:number;value:number;low:number};chartData:{date:string;incoming:number;outgoing:number}[];movements:StockMovement[];topOutgoingProducts:{id:string;name:string;quantity:number}[];topPackages:{id:string;name:string;quantity:number;orders:number}[];data:Data;close:()=>void}){
  const [phone,setPhone]=useState("");const [error,setError]=useState("");const filename=`inventory-report-${range.from}-${range.to}.pdf`;useEffect(()=>setPhone(localStorage.getItem("inventory-report-whatsapp-phone")??""),[]);
  function pdf(){return createReportPdf({locale,range,branchName,stats,chartData,movements,topOutgoingProducts,topPackages,data})}
  function download(blob:Blob){const link=document.createElement("a");link.href=URL.createObjectURL(blob);link.download=filename;link.click();setTimeout(()=>URL.revokeObjectURL(link.href),1000)}
  function send(){let number=phone.replace(/\D/g,"");if(number.startsWith("0"))number=`20${number.slice(1)}`;if(number.length<10){setError(locale==="ar"?"اكتب رقم واتساب صحيح مع كود الدولة، مثال: 201000000000":"Enter a valid WhatsApp number with country code");return}localStorage.setItem("inventory-report-whatsapp-phone",number);const blob=pdf();download(blob);const message=locale==="ar"?`تقرير المخزون (${range.from} إلى ${range.to}) — ${branchName}. تم تنزيل ملف PDF، برجاء إرفاقه في المحادثة.`:`Inventory report (${range.from} to ${range.to}) — ${branchName}. The PDF was downloaded; please attach it to this chat.`;window.open(`https://wa.me/${number}?text=${encodeURIComponent(message)}`,"_blank","noopener,noreferrer");close()}
  async function share(){try{const blob=pdf();const file=new File([blob],filename,{type:"application/pdf"});if(!navigator.canShare?.({files:[file]})){setError(locale==="ar"?"المشاركة المباشرة غير مدعومة على هذا الجهاز؛ استخدم زر تنزيل PDF وفتح واتساب.":"Direct sharing is not supported on this device.");return}await navigator.share({title:locale==="ar"?"تقرير المخزون":"Inventory report",text:`${range.from} — ${range.to}`,files:[file]})}catch(e){if((e as Error).name!=="AbortError")setError(locale==="ar"?"تعذرت مشاركة الملف":"Could not share the file")}}
  return <div className="fixed inset-0 z-50 grid place-items-center bg-slate-950/60 p-3"><section className="card w-full max-w-lg p-6"><div className="flex items-start"><div><h2 className="text-xl font-bold">{locale==="ar"?"إرسال التقرير واتساب":"Send report via WhatsApp"}</h2><p className="mt-1 text-sm text-slate-500">{range.from} — {range.to} · {branchName}</p></div><button onClick={close} className="ms-auto p-2"><X/></button></div><label className="mt-6 block text-sm">{locale==="ar"?"رقم الواتساب بكود الدولة":"WhatsApp number with country code"}<input autoFocus inputMode="tel" className="input mt-2 text-left" dir="ltr" placeholder="201000000000" value={phone} onChange={e=>setPhone(e.target.value)}/></label><p className="mt-3 rounded-xl bg-amber-50 p-3 text-sm text-amber-800 dark:bg-amber-950/30 dark:text-amber-200">{locale==="ar"?"على الكمبيوتر: سيُنزل التقرير PDF ويفتح محادثة الرقم، ثم أرفق الملف الذي تم تنزيله. الإرفاق التلقائي يحتاج WhatsApp Business API وسيرفر.":"On desktop, the PDF downloads and the chat opens; attach the downloaded file. Automatic attachment requires WhatsApp Business API and a server."}</p>{error&&<p className="mt-3 rounded-xl bg-red-50 p-3 text-sm text-red-700">{error}</p>}<div className="mt-6 flex flex-wrap justify-end gap-2"><button onClick={close} className="btn-secondary">{locale==="ar"?"إلغاء":"Cancel"}</button>{typeof navigator!=="undefined"&&"share" in navigator&&<button onClick={()=>void share()} className="btn-secondary"><FileDown size={17}/>{locale==="ar"?"مشاركة PDF مباشرة":"Share PDF directly"}</button>}<button onClick={send} className="btn-primary"><MessageCircle size={17}/>{locale==="ar"?"تنزيل PDF وفتح واتساب":"Download PDF & open WhatsApp"}</button></div></section></div>;
}

function createReportPdf({locale,range,branchName,stats,chartData,movements,topOutgoingProducts,topPackages,data}:{locale:Locale;range:{from:string;to:string};branchName:string;stats:{incoming:number;outgoing:number;value:number;low:number};chartData:{date:string;incoming:number;outgoing:number}[];movements:StockMovement[];topOutgoingProducts:{id:string;name:string;quantity:number}[];topPackages:{id:string;name:string;quantity:number;orders:number}[];data:Data}){
  const width=1240,height=1754,rtl=locale==="ar";const chunks:StockMovement[][]=[movements.slice(0,12)];for(let i=12;i<movements.length;i+=24)chunks.push(movements.slice(i,i+24));if(!chunks.length)chunks.push([]);const doc=new jsPDF({orientation:"portrait",unit:"px",format:[width,height],compress:true});
  chunks.forEach((rows,page)=>{const canvas=document.createElement("canvas");canvas.width=width;canvas.height=height;const ctx=canvas.getContext("2d")!;ctx.fillStyle="#ffffff";ctx.fillRect(0,0,width,height);ctx.direction=rtl?"rtl":"ltr";const edge=70;const textX=rtl?width-edge:edge;ctx.textAlign=rtl?"right":"left";ctx.fillStyle="#0f766e";ctx.fillRect(0,0,width,18);ctx.fillStyle="#0f172a";ctx.font="bold 42px Arial";ctx.fillText(locale==="ar"?"تقرير حركة المخزون":"Inventory Movement Report",textX,85);ctx.font="24px Arial";ctx.fillStyle="#475569";ctx.fillText(`${range.from} — ${range.to}  |  ${branchName}`,textX,130);
    let y=185;if(page===0){const cards=[{label:locale==="ar"?"الوارد":"Incoming",value:stats.incoming,color:"#059669"},{label:locale==="ar"?"الصادر":"Outgoing",value:stats.outgoing,color:"#ea580c"},{label:locale==="ar"?"قيمة المخزون":"Stock value",value:`${stats.value.toLocaleString()} EGP`,color:"#0f766e"},{label:locale==="ar"?"منخفض / نافد":"Low / out",value:stats.low,color:"#d97706"}];cards.forEach((card,i)=>{const x=edge+i*278;ctx.fillStyle="#f8fafc";ctx.fillRect(x,y,250,120);ctx.fillStyle="#64748b";ctx.font="20px Arial";ctx.textAlign="center";ctx.fillText(String(card.label),x+125,y+38);ctx.fillStyle=card.color;ctx.font="bold 29px Arial";ctx.fillText(String(card.value),x+125,y+83)});y=350;ctx.textAlign=rtl?"right":"left";ctx.fillStyle="#0f172a";ctx.font="bold 26px Arial";ctx.fillText(locale==="ar"?"الوارد والصادر حسب التاريخ":"Incoming and outgoing by date",textX,y);const max=Math.max(1,...chartData.flatMap(x=>[x.incoming,x.outgoing]));const plotY=y+35,plotH=250,plotW=width-edge*2;ctx.strokeStyle="#cbd5e1";ctx.strokeRect(edge,plotY,plotW,plotH);chartData.slice(-20).forEach((d,i,all)=>{const slot=plotW/Math.max(all.length,1),bar=Math.min(22,slot*.3),x=edge+i*slot+slot*.25;ctx.fillStyle="#10b981";ctx.fillRect(x,plotY+plotH-d.incoming/max*(plotH-35),bar,d.incoming/max*(plotH-35));ctx.fillStyle="#f97316";ctx.fillRect(x+bar+4,plotY+plotH-d.outgoing/max*(plotH-35),bar,d.outgoing/max*(plotH-35))});y=675;const rankingPanels=[{title:locale==="ar"?"أكثر الأصناف خروجًا":"Top outgoing products",items:topOutgoingProducts.slice(0,3).map(x=>`${x.name}: ${x.quantity}`),color:"#0f766e"},{title:locale==="ar"?"أكثر الباكيدجات طلبًا":"Most requested packages",items:topPackages.slice(0,3).map(x=>`${x.name}: ${x.quantity} (${x.orders})`),color:"#7c3aed"}];rankingPanels.forEach((panel,index)=>{const x=edge+index*555;ctx.fillStyle="#f8fafc";ctx.fillRect(x,y,520,145);ctx.fillStyle=panel.color;ctx.font="bold 22px Arial";ctx.textAlign="center";ctx.fillText(panel.title,x+260,y+32);ctx.fillStyle="#334155";ctx.font="17px Arial";if(panel.items.length)panel.items.forEach((item,i)=>ctx.fillText(`${i+1}. ${item}`,x+260,y+65+i*25));else ctx.fillText(locale==="ar"?"لا توجد بيانات":"No data",x+260,y+85)});y=850}else y=190;
    ctx.textAlign=rtl?"right":"left";ctx.fillStyle="#0f172a";ctx.font="bold 26px Arial";ctx.fillText(locale==="ar"?"تفاصيل الحركات":"Movement details",textX,y);y+=30;ctx.fillStyle="#0f766e";ctx.fillRect(edge,y,width-edge*2,46);const headers=rtl?["المستخدم","الكمية","المنتج","الفرع","النوع","المرجع","التاريخ"]:["Date","Reference","Type","Branch","Product","Quantity","User"];const colW=(width-edge*2)/headers.length;ctx.fillStyle="#fff";ctx.font="bold 17px Arial";ctx.textAlign="center";headers.forEach((h,i)=>ctx.fillText(h,edge+colW*i+colW/2,y+29));y+=46;rows.forEach((m,index)=>{ctx.fillStyle=index%2?"#f8fafc":"#ffffff";ctx.fillRect(edge,y,width-edge*2,48);const cells=rtl?[m.user,m.quantity,name(data.products,m.productId,locale),name(data.branches,m.branchId,locale),m.type,m.reference,m.date]:[m.date,m.reference,m.type,name(data.branches,m.branchId,locale),name(data.products,m.productId,locale),m.quantity,m.user];ctx.fillStyle="#334155";ctx.font="16px Arial";ctx.textAlign="center";cells.forEach((cell,i)=>{const value=String(cell);ctx.fillText(value.length>20?`${value.slice(0,18)}…`:value,edge+colW*i+colW/2,y+30)});y+=48});ctx.fillStyle="#94a3b8";ctx.font="16px Arial";ctx.textAlign="center";ctx.fillText(`${page+1} / ${chunks.length}`,width/2,height-35);if(page>0)doc.addPage([width,height],"portrait");doc.addImage(canvas.toDataURL("image/jpeg",.9),"JPEG",0,0,width,height,undefined,"FAST")});return doc.output("blob")
}
function SettingsPage({locale,reset}:{locale:Locale;reset:()=>void}){return <div className="grid gap-6 lg:grid-cols-2"><section className="card p-6"><h2 className="text-lg font-bold">{locale==="ar"?"إعدادات النظام":"System settings"}</h2><label className="mt-6 block text-sm"><span>{locale==="ar"?"اسم الشركة":"Company name"}</span><input className="input mt-2" defaultValue={locale==="ar"?"الشركة المصرية للتجارة":"Egyptian Trading Co."}/></label><label className="mt-4 block text-sm"><span>{locale==="ar"?"العملة":"Currency"}</span><select className="input mt-2"><option>EGP — Egyptian Pound</option></select></label><button className="btn-primary mt-5">{locale==="ar"?"حفظ الإعدادات":"Save settings"}</button></section><section className="card p-6"><h2 className="text-lg font-bold">{locale==="ar"?"بيانات العرض التجريبي":"Demo data"}</h2><p className="mt-3 text-sm text-slate-500">{locale==="ar"?"إعادة جميع خيارات الواجهة إلى حالتها الأصلية.":"Restore all frontend preferences to their initial state."}</p><button onClick={reset} className="btn-secondary mt-5 text-red-600"><RefreshCw size={17}/>{locale==="ar"?"إعادة ضبط البيانات":"Reset demo data"}</button></section></div>}
function Profile({locale}:{locale:Locale}){return <section className="card mx-auto max-w-2xl p-7"><div className="flex items-center gap-4"><span className="grid h-20 w-20 place-items-center rounded-2xl bg-brand-100 text-brand-700"><UserRound size={38}/></span><div><h2 className="text-2xl font-bold">{locale==="ar"?"مدير النظام":"System Admin"}</h2><p className="text-slate-500">admin@demo.com</p></div></div><div className="mt-8 grid gap-4 sm:grid-cols-2"><label className="text-sm">{locale==="ar"?"الاسم":"Name"}<input className="input mt-2" defaultValue={locale==="ar"?"مدير النظام":"System Admin"}/></label><label className="text-sm">{locale==="ar"?"رقم الهاتف":"Phone"}<input className="input mt-2" defaultValue="01000000000"/></label></div><button className="btn-primary mt-6">{locale==="ar"?"حفظ التغييرات":"Save changes"}</button></section>}

function ListLayout({title,search,setSearch,actions,filters,children}:{title:string;search:string;setSearch:(v:string)=>void;actions?:React.ReactNode;filters?:React.ReactNode;children:React.ReactNode}){const t=useTranslations();return <section><div className="mb-5 flex flex-wrap items-center gap-3"><div className="min-w-0"><h2 className="break-words text-xl font-bold sm:text-2xl">{title}</h2><p className="text-sm text-slate-500">{t("demo")}</p></div><div className="no-print flex w-full flex-wrap gap-2 sm:ms-auto sm:w-auto">{actions}</div></div><div className="card overflow-hidden"><div className="flex flex-wrap gap-3 border-b border-slate-200 p-3 dark:border-slate-800 sm:p-4"><div className="relative min-w-0 flex-1 basis-full sm:min-w-60 sm:basis-auto"><Search className="absolute start-3 top-3 text-slate-400" size={18}/><input className="input ps-10" placeholder={t("search")} value={search} onChange={e=>setSearch(e.target.value)}/></div>{filters}</div>{children}</div></section>}
function Table({headers,children,empty}:{headers:string[];children:React.ReactNode;empty:boolean}){const t=useTranslations();return <div className="table-scroll overflow-x-auto"><table className="w-full min-w-[680px] text-sm md:min-w-[760px]"><thead className="sticky top-0 bg-slate-50 text-slate-500 dark:bg-slate-800"><tr>{headers.map(h=><th className="whitespace-nowrap px-4 py-3 text-start font-semibold" key={h}>{h}</th>)}</tr></thead><tbody className="divide-y divide-slate-100 dark:divide-slate-800">{empty?<tr><td colSpan={headers.length} className="p-16 text-center text-slate-500">{t("empty")}</td></tr>:children}</tbody></table></div>}
function Cell({children,strong=false}:{children:React.ReactNode;strong?:boolean}){return <td className={`whitespace-nowrap px-4 py-3.5 ${strong?"font-semibold":"text-slate-600 dark:text-slate-300"}`}>{children}</td>}
function Status({value}:{value:string}){const colors:Record<string,string>={active:"bg-emerald-100 text-emerald-700",available:"bg-emerald-100 text-emerald-700",received:"bg-emerald-100 text-emerald-700",posted:"bg-emerald-100 text-emerald-700",low:"bg-amber-100 text-amber-700",draft:"bg-slate-100 text-slate-600",sent:"bg-blue-100 text-blue-700",out:"bg-red-100 text-red-700",inactive:"bg-red-100 text-red-700",cancelled:"bg-red-100 text-red-700",overstock:"bg-violet-100 text-violet-700"};return <span className={`badge ${colors[value]??"bg-slate-100"}`}>{value}</span>}
function SimpleModal({locale,title,close,save}:{locale:Locale;title:string;close:()=>void;save:(v:string)=>void}){const [value,setValue]=useState("");return <div className="fixed inset-0 z-50 grid place-items-center bg-slate-950/50 p-4"><form onSubmit={e=>{e.preventDefault();if(value.trim())save(value)}} className="card w-full max-w-md p-6"><div className="flex items-center"><h2 className="text-xl font-bold">{title}</h2><button type="button" onClick={close} className="ms-auto"><X/></button></div><label className="mt-6 block text-sm">{locale==="ar"?"الاسم":"Name"}<input autoFocus required minLength={2} className="input mt-2" value={value} onChange={e=>setValue(e.target.value)}/></label><p className="mt-3 text-xs text-slate-500">{locale==="ar"?"سيتم حفظ العملية في حالة الواجهة التجريبية فقط.":"This will be saved in frontend demo state only."}</p><div className="mt-6 flex justify-end gap-2"><button type="button" onClick={close} className="btn-secondary">{locale==="ar"?"إلغاء":"Cancel"}</button><button className="btn-primary">{locale==="ar"?"حفظ":"Save"}</button></div></form></div>}
function name(items:(Branch|Product)[],id:string,locale:Locale){const x=items.find(i=>i.id===id);return x?(locale==="ar"?x.nameAr:x.nameEn):"—"}
function packageCapacity(data:Data,pkg:ProductPackage,branchId:string){if(!pkg.items.length)return 0;return Math.max(0,Math.min(...pkg.items.map(item=>Math.floor((data.inventory.find(i=>i.branchId===branchId&&i.productId===item.productId)?.availableQuantity??0)/item.quantity))))}
function barterOutgoing(barter:ProductBarter){return barter.outgoingItems?.length?barter.outgoingItems:[{productId:barter.primaryProductId,quantity:barter.primaryQuantity}]}
function ProductImage({product,size="sm"}:{product:Pick<Product,"imageUrl">;size?:"sm"|"lg"}){const classes=size==="lg"?"h-20 w-20":"h-11 w-11";return product.imageUrl?<span role="img" aria-label="Product" className={`${classes} block rounded-xl bg-cover bg-center`} style={{backgroundImage:`url(${product.imageUrl})`}}/>:<span className={`${classes} grid place-items-center rounded-xl bg-slate-100 text-slate-400 dark:bg-slate-800`}><Package size={size==="lg"?30:20}/></span>}
function compressProductImage(file:File){return new Promise<string>((resolve,reject)=>{const reader=new FileReader();reader.onerror=()=>reject(new Error("Image read failed"));reader.onload=()=>{const image=new Image();image.onerror=()=>reject(new Error("Invalid image"));image.onload=()=>{const max=320;const scale=Math.min(1,max/Math.max(image.width,image.height));const canvas=document.createElement("canvas");canvas.width=Math.round(image.width*scale);canvas.height=Math.round(image.height*scale);canvas.getContext("2d")?.drawImage(image,0,0,canvas.width,canvas.height);resolve(canvas.toDataURL("image/jpeg",.76))};image.src=String(reader.result)};reader.readAsDataURL(file)})}
function downloadCSV(filename:string,lines:string[]){const blob=new Blob(["\uFEFF"+lines.join("\n")],{type:"text/csv;charset=utf-8"});const a=document.createElement("a");a.href=URL.createObjectURL(blob);a.download=filename;a.click();URL.revokeObjectURL(a.href)}
async function downloadExcel(filename:string,headers:string[],rows:(string|number)[][]){const {default:writeXlsxFile}=await import("write-excel-file/browser");const headerStyle={fontWeight:"bold" as const,backgroundColor:"#0F766E",color:"#FFFFFF",align:"center" as const,verticalAlign:"center" as const,height:32};const sheet:SheetData=[[...headers.map(value=>({value,type:String,...headerStyle}))],...rows.map(row=>row.map(value=>typeof value==="number"?{value,type:Number,format:"#,##0.###",align:"center" as const}:{value:String(value),type:String,align:"center" as const,wrap:true}))];await writeXlsxFile(sheet,{sheet:"Inventory Report",stickyRowsCount:1,rightToLeft:/[\u0600-\u06ff]/.test(headers[0]??""),showGridLines:false,columns:headers.map((_,index)=>({width:index===2||index===4?24:index===5?14:18}))}).toFile(filename)}
function printVoucher(transfer:Transfer,data:Data,locale:Locale){
  const product=transfer.productId?name(data.products,transfer.productId,locale):"—";const from=name(data.branches,transfer.fromBranchId,locale);const to=name(data.branches,transfer.toBranchId,locale);const win=window.open("","_blank","width=760,height=700");if(!win)return;
  const safe=(value:string|number)=>String(value).replace(/[&<>"']/g,char=>({"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#039;"}[char]!));
  win.document.write(`<!doctype html><html dir="${locale==="ar"?"rtl":"ltr"}"><head><meta charset="utf-8"><title>${safe(transfer.number)}</title><style>body{font-family:Arial;padding:40px;color:#172033}h1{border-bottom:2px solid #10b981;padding-bottom:15px}table{width:100%;border-collapse:collapse;margin-top:25px}td,th{border:1px solid #ccd4df;padding:13px;text-align:start}.sign{display:flex;justify-content:space-between;margin-top:70px}</style></head><body><h1>${locale==="ar"?"إذن صرف مخزني":"Stock Issue Voucher"}</h1><p><b>${locale==="ar"?"رقم الإذن":"Voucher No."}:</b> ${safe(transfer.number)}</p><p><b>${locale==="ar"?"التاريخ":"Date"}:</b> ${safe(transfer.date)}</p><table><tr><th>${locale==="ar"?"السلعة":"Product"}</th><th>${locale==="ar"?"الكمية":"Quantity"}</th><th>${locale==="ar"?"من":"From"}</th><th>${locale==="ar"?"إلى":"To"}</th></tr><tr><td>${safe(product)}</td><td>${safe(transfer.quantity??0)}</td><td>${safe(from)}</td><td>${safe(to)}</td></tr></table><div class="sign"><span>${locale==="ar"?"توقيع أمين المخزن":"Storekeeper signature"}: ................</span><span>${locale==="ar"?"توقيع المستلم":"Receiver signature"}: ................</span></div><script>window.print()<\/script></body></html>`);win.document.close();
}

function printStockIssue(issue:StockIssue,data:Data,locale:Locale){const win=window.open("","_blank","width=900,height=800");if(!win)return;const safe=(value:string|number)=>String(value).replace(/[&<>"']/g,char=>({"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#039;"}[char]!));const rows=issue.items.map((item,index)=>`<tr><td>${index+1}</td><td>${safe(name(data.products,item.productId,locale))}</td><td>${item.quantity}</td><td>${item.unitPrice.toLocaleString()}</td><td>${(item.quantity*item.unitPrice).toLocaleString()}</td></tr>`).join("");win.document.write(`<!doctype html><html dir="${locale==="ar"?"rtl":"ltr"}"><head><meta charset="utf-8"><title>${safe(issue.number)}</title><style>body{font-family:Arial;padding:35px;color:#172033}.head{display:flex;justify-content:space-between;border-bottom:3px solid #10b981;padding-bottom:18px}h1{margin:0}.meta{display:grid;grid-template-columns:1fr 1fr;gap:12px;margin:25px 0}.box{border:1px solid #d5dbe5;padding:12px;border-radius:8px}table{width:100%;border-collapse:collapse}td,th{border:1px solid #ccd4df;padding:11px;text-align:start}th{background:#f1f5f9}.total{text-align:end;font-size:22px;margin-top:20px}.sign{display:flex;justify-content:space-between;margin-top:70px}</style></head><body><div class="head"><div><h1>${locale==="ar"?"إذن صرف مخزني":"Stock Issue Voucher"}</h1><p>${issue.issueType==="sale"?(locale==="ar"?"بيع لعميل":"Customer Sale"):(locale==="ar"?"صرف داخلي":"Internal Issue")}</p></div><strong>${safe(issue.number)}</strong></div><div class="meta"><div class="box"><b>${locale==="ar"?"المخزن الصارف":"Warehouse"}:</b> ${safe(name(data.branches,issue.branchId,locale))}</div><div class="box"><b>${locale==="ar"?"التاريخ":"Date"}:</b> ${safe(issue.date)}</div><div class="box"><b>${locale==="ar"?"العميل/الجهة":"Customer/Recipient"}:</b> ${safe(issue.customerName)}</div><div class="box"><b>${locale==="ar"?"الحالة":"Status"}:</b> ${locale==="ar"?"معتمد":"Posted"}</div></div><table><thead><tr><th>#</th><th>${locale==="ar"?"الصنف":"Product"}</th><th>${locale==="ar"?"الكمية":"Qty"}</th><th>${locale==="ar"?"سعر الوحدة":"Unit price"}</th><th>${locale==="ar"?"الإجمالي":"Total"}</th></tr></thead><tbody>${rows}</tbody></table><p class="total"><b>${locale==="ar"?"الإجمالي النهائي":"Grand total"}: ${issue.total.toLocaleString()} EGP</b></p><p>${locale==="ar"?"ملاحظات":"Notes"}: ${safe(issue.notes||"—")}</p><div class="sign"><span>${locale==="ar"?"أمين المخزن":"Storekeeper"}: ................</span><span>${locale==="ar"?"المستلم":"Receiver"}: ................</span><span>${locale==="ar"?"الاعتماد":"Approval"}: ................</span></div><script>window.print()<\/script></body></html>`);win.document.close()}

function printBarter(barter:ProductBarter,data:Data,locale:Locale){const win=window.open("","_blank","width=850,height=750");if(!win)return;const safe=(value:string|number)=>String(value).replace(/[&<>"']/g,char=>({"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#039;"}[char]!));win.document.write(`<!doctype html><html dir="${locale==="ar"?"rtl":"ltr"}"><head><meta charset="utf-8"><title>${safe(barter.number)}</title><style>body{font-family:Arial;padding:40px;color:#172033}header{display:flex;justify-content:space-between;border-bottom:3px solid #10b981;padding-bottom:18px}.meta{display:grid;grid-template-columns:1fr 1fr;gap:12px;margin:24px 0}.box{border:1px solid #ccd4df;padding:12px;border-radius:8px}.rule{text-align:center;background:#ecfdf5;border:2px solid #a7f3d0;padding:22px;border-radius:12px;font-size:20px;margin:25px 0}table{width:100%;border-collapse:collapse}td,th{border:1px solid #ccd4df;padding:12px;text-align:start}th{background:#f1f5f9}.sign{display:flex;justify-content:space-between;margin-top:70px}</style></head><body><header><div><h1>${locale==="ar"?"إذن مقايضة منتجات":"Product Barter Voucher"}</h1><p>${safe(name(data.branches,barter.branchId,locale))}</p></div><strong>${safe(barter.number)}</strong></header><div class="meta"><div class="box"><b>${locale==="ar"?"التاريخ":"Date"}:</b> ${barter.date}</div><div class="box"><b>${locale==="ar"?"العميل/الجهة":"Customer"}:</b> ${safe(barter.customerName)}</div></div><div class="rule">${barter.ratioBase} ${safe(name(data.products,barter.primaryProductId,locale))} ${locale==="ar"?"خارج":"out"} = ${barter.ratioExchange} ${safe(name(data.products,barter.exchangeProductId,locale))} ${locale==="ar"?"وارد":"in"}</div><table><tr><th>${locale==="ar"?"الحركة":"Movement"}</th><th>${locale==="ar"?"الصنف":"Product"}</th><th>${locale==="ar"?"الكمية":"Quantity"}</th></tr><tr><td>${locale==="ar"?"صادر من المخزن":"Stock out"}</td><td>${safe(name(data.products,barter.primaryProductId,locale))}</td><td>-${barter.primaryQuantity}</td></tr><tr><td>${locale==="ar"?"وارد إلى المخزن":"Stock in"}</td><td>${safe(name(data.products,barter.exchangeProductId,locale))}</td><td>+${barter.exchangeQuantity}</td></tr></table><p>${locale==="ar"?"ملاحظات":"Notes"}: ${safe(barter.notes||"—")}</p><div class="sign"><span>${locale==="ar"?"أمين المخزن":"Storekeeper"}: ............</span><span>${locale==="ar"?"الطرف الآخر":"Other party"}: ............</span><span>${locale==="ar"?"الاعتماد":"Approval"}: ............</span></div><script>window.print()<\/script></body></html>`);win.document.close()}

function mergeDuplicateProducts(data:Data):Data{
  const canonical=new Map<string,Product>();const idMap=new Map<string,string>();const products:Product[]=[];
  for(const product of data.products){const key=(product.nameAr||product.nameEn||product.sku).trim().toLowerCase();const existing=canonical.get(key);if(existing){idMap.set(product.id,existing.id)}else{canonical.set(key,product);idMap.set(product.id,product.id);products.push(product)}}
  const balances=new Map<string,InventoryBalance>();
  for(const item of data.inventory){const productId=idMap.get(item.productId)??item.productId;const key=`${item.branchId}|${productId}`;const existing=balances.get(key);if(!existing){balances.set(key,{...item,productId});continue}const current=existing.currentQuantity+item.currentQuantity;const reserved=existing.reservedQuantity+item.reservedQuantity;const value=existing.inventoryValue+item.inventoryValue;const available=current-reserved;balances.set(key,{...existing,currentQuantity:current,reservedQuantity:reserved,availableQuantity:available,averageCost:current?value/current:existing.averageCost,inventoryValue:value,status:getStockStatus(available,existing.minimumQuantity,existing.maximumQuantity)})}
  return {...data,products,inventory:[...balances.values()],movements:data.movements.map(m=>({...m,productId:idMap.get(m.productId)??m.productId})),transfers:data.transfers.map(x=>({...x,productId:x.productId?(idMap.get(x.productId)??x.productId):undefined})),stockIssues:data.stockIssues.map(issue=>({...issue,items:issue.items.map(item=>({...item,productId:idMap.get(item.productId)??item.productId}))})),barters:data.barters.map(x=>({...x,primaryProductId:idMap.get(x.primaryProductId)??x.primaryProductId,exchangeProductId:idMap.get(x.exchangeProductId)??x.exchangeProductId,outgoingItems:x.outgoingItems?.map(item=>({...item,productId:idMap.get(item.productId)??item.productId})),incomingItems:x.incomingItems?.map(item=>({...item,productId:idMap.get(item.productId)??item.productId}))})),packages:data.packages.map(pkg=>({...pkg,items:pkg.items.map(item=>({...item,productId:idMap.get(item.productId)??item.productId})),returnProductId:idMap.get(pkg.returnProductId)??pkg.returnProductId})),packageIssues:data.packageIssues.map(issue=>({...issue,items:issue.items.map(item=>({...item,productId:idMap.get(item.productId)??item.productId})),returnProductId:idMap.get(issue.returnProductId)??issue.returnProductId}))};
}
